CREATE TABLE `intentos_examen` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `examen_id` bigint NOT NULL,
  `estudiante_id` bigint NOT NULL,
  `estado` varchar(20) NOT NULL,
  `started_at` datetime(6) NOT NULL,
  `deadline_at` datetime(6) DEFAULT NULL,
  `first_submit_attempt_at` datetime(6) DEFAULT NULL,
  `submitted_at` datetime(6) DEFAULT NULL,
  `blocked_at` datetime(6) DEFAULT NULL,
  `block_reason` varchar(255) DEFAULT NULL,
  `reopened_at` datetime(6) DEFAULT NULL,
  `reopen_count` int NOT NULL DEFAULT '0',
  `extra_minutes_total` int NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_intento_examen_estudiante` (`examen_id`,`estudiante_id`),
  KEY `fk_intento_estudiante` (`estudiante_id`),
  KEY `idx_intentos_examen_config` (`examen_id`,`estudiante_id`),
  CONSTRAINT `fk_intento_estudiante` FOREIGN KEY (`estudiante_id`) REFERENCES `estudiantes` (`id`),
  CONSTRAINT `fk_intento_examen` FOREIGN KEY (`examen_id`) REFERENCES `examenes` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=327 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
