INSERT INTO `preguntas` VALUES (253,1,'¿Cuál de estos es un error de lógica y no de sintaxis?','Olvidar un punto y coma.','Escribir \'whle\' en lugar de \'while\'.','Calcular el promedio dividiendo la suma por un número incorrecto de elementos.','No cerrar un paréntesis.','C','Los errores de sintaxis impiden que el programa corra. Los de lógica permiten que corra, pero dan resultados incorrectos.'),(254,1,'¿Qué resultado arroja la expresión lógica: (5 > 3) AND (10 < 8)?','True','False','Error de sintaxis','15','B','En una operación AND, ambas condiciones deben ser verdaderas. Aunque (5 > 3) es verdadero, (10 < 8) es falso, invalidando toda la expresión.'),(255,1,'¿Qué sucede en un flujo de control si la condición de un \'If\' es falsa y no existe un \'Else\'?','El programa se detiene con un error.','El programa salta el bloque de código del If y continúa con la siguiente instrucción fuera de él.','El programa vuelve a evaluar la condición indefinidamente.','Se ejecuta el código dentro del If por defecto.','B','El bloque \'Else\' es opcional. Si la condición no se cumple y no hay alternativa definida, el flujo simplemente sigue su curso normal.'),(256,1,'En el contexto de ciclos, ¿qué es un \'Bucle Infinito\'?','Un ciclo que procesa grandes cantidades de datos.','Un error de lógica donde la condición de salida nunca se vuelve falsa.','Un ciclo diseñado para durar exactamente 24 horas.','Una estructura que usa demasiada memoria RAM.','B','Si la variable de control nunca cambia o la condición siempre es verdadera, el programa queda atrapado, consumiendo recursos sin finalizar.'),(257,1,'¿Cuál es la principal característica del ciclo \'While\'?','Se ejecuta un número exacto de veces definido al inicio.','Se ejecuta mientras una condición sea verdadera, evaluándola antes de cada iteración.','Solo se utiliza para recorrer arreglos.','Se ejecuta al menos una vez, sin importar la condición.','B','El \'While\' es un ciclo de pre-condición. Si la condición es falsa desde el principio, el bloque de código nunca se ejecuta.'),(258,1,'¿Cuál es la función principal de un algoritmo?','Diseñar interfaces gráficas atractivas.','Escribir código que solo las computadoras entiendan.','Definir una serie de pasos ordenados y finitos para resolver un problema.','Aumentar la velocidad del procesador.','C','Un algoritmo es una receta lógica: debe ser finito, preciso y resolver una situación específica independientemente del lenguaje.'),(259,1,'¿Cuál es el propósito del operador módulo (%) en programación?','Calcular el porcentaje de un número.','Dividir dos números y devolver el cociente entero.','Obtener el residuo o resto de una división entera.','Elevar un número a una potencia.','C','El módulo es fundamental para lógica de ciclos y condicionales, como determinar si un número es par (n % 2 == 0).'),(260,1,'En lógica de programación, ¿qué representa el proceso de \'Inicialización\'?','Es el acto de borrar el contenido de la memoria caché.','Asignar un tipo de dato a una variable sin darle un valor.','Asignar un valor inicial a una variable antes de ser utilizada por primera vez.','El momento en que el código se traduce a lenguaje máquina.','C','Utilizar una variable sin inicializar suele provocar errores de \'basura en memoria\' o valores nulos (null/undefined), por lo que darle un valor inicial es una buena práctica esencial.'),(261,1,'¿Cuál es el valor de la variable \'x\' tras ejecutar: x = 10; x = x + 5; x = x * 2;?','20','25','30','15','C','Sigue un orden secuencial: 10 + 5 = 15; luego 15 * 2 = 30.'),(262,1,'De acuerdo a las buenas prácticas (CamelCase), ¿cuál sería el nombre correcto para una variable que guarda el precio final de un producto?','PRECIO_FINAL','precio_final','precioFinal','PrecioFinal','C','CamelCase inicia con minúscula y cada palabra siguiente con mayúscula. La opción D (PascalCase) suele usarse para clases, y la A (SNAKE_CASE_MAYUS) para constantes.'),(263,1,'¿Qué es un \'Acumulador\'?','Una variable que siempre aumenta de 1 en 1.','Una estructura que guarda nombres de variables.','Una variable que suma valores variables en cada iteración.','Un método para borrar la memoria.','C','A diferencia del contador, el acumulador suma montos distintos (ej: total = total + precioArticulo).'),(264,1,'¿Para qué sirve la estructura \'Switch\' o \'Según sea\'?','Para repetir un bloque de código muchas veces.','Para manejar múltiples condiciones basadas en el valor de una sola expresión.','Para declarar variables globales.','Para conectar la base de datos.','B','Es una alternativa más limpia a múltiples \'If-Else\' anidados cuando se evalúa una misma variable contra varios valores posibles.'),(265,1,'¿Qué diferencia al ciclo \'Do-While\' del ciclo \'While\'?','El Do-While es más rápido.','El Do-While evalúa la condición al final, garantizando al menos una ejecución del bloque.','El While solo funciona con números enteros.','No hay diferencia, son sinónimos en todos los lenguajes.','B','A diferencia del \'While\' estándar, el \'Do-While\' ejecuta el cuerpo del ciclo primero y luego pregunta si debe continuar.'),(266,1,'Si necesitas almacenar la cantidad de hijos de una persona, ¿cuál es el tipo de dato más adecuado?','Flotante (Float/Double)','Booleano','Entero (Integer)','Cadena (String)','C','La cantidad de hijos es una unidad discreta y contable que no admite decimales, por lo que un entero es el tipo de dato óptimo.'),(267,1,'¿Cuál es el resultado de la concatenación de \'Hola\' + \'Mundo\'?','HolaMundo','Hola Mundo','Error: no se pueden sumar palabras.','2','A','La concatenación une las cadenas tal cual están. Si no hay un espacio dentro de las comillas, los textos se pegan directamente.'),(268,1,'¿Qué es una \'Prueba de Escritorio\'?','Limpiar el lugar de trabajo del programador.','Seguir manualmente los pasos de un algoritmo con valores de ejemplo para verificar el resultado.','Un examen para comprar una computadora nueva.','Instalar el software en la PC del cliente.','B','Es la técnica manual para validar la lógica antes de programar, simulando cómo cambiarían las variables paso a paso.'),(269,1,'Si un ciclo debe ejecutarse mientras la variable \'energía\' sea mayor a 0, ¿cuál es la condición correcta?','energia == 0','energia < 0','energia > 0','energia != 0','C','La condición debe ser verdadera para que el ciclo continúe; por lo tanto, \'energia > 0\' es la que valida la permanencia.'),(270,1,'¿Cuál es el primer paso recomendado antes de escribir el código de un algoritmo complejo?','Compilar el programa.','Definir las variables globales en la base de datos.','Realizar un análisis del problema y diseñar un diagrama de flujo o pseudocódigo.','Comprar una licencia de un lenguaje de programación.','C','La planeación mediante pseudocódigo evita errores de lógica estructural que son difíciles de corregir una vez codificados.'),(271,1,'¿Qué es la indentación (sangría) y por qué es importante?','Es un tipo de variable para textos largos.','Es el espacio al inicio de las líneas para indicar qué bloques de código pertenecen a otros.','Es una función para imprimir en pantalla.','Es un método para encriptar contraseñas.','B','La indentación mejora la legibilidad y, en lenguajes como Python, es obligatoria para definir la jerarquía del código.'),(272,1,'¿Qué es un \'Contador\' en programación?','Una variable que se incrementa o decrementa en un valor constante (usualmente 1).','Una función que mide el tiempo de ejecución.','Una variable que guarda la suma de valores variables.','Un tipo de dato especial para finanzas.','A','Los contadores se usan para llevar el registro de iteraciones (ej: i = i + 1).'),(274,1,'¿Qué operador se utiliza para verificar si dos valores son DISTINTOS?','==','=','!=','<>','C','El operador de desigualdad es \'!=\' en la mayoría de lenguajes modernos (C, Java, Python, JS).'),(275,1,'En la jerarquía de operadores matemáticos, ¿cuál se ejecuta primero?','Suma y Resta.','Multiplicación y División.','Paréntesis.','Asignación (=).','C','Los paréntesis tienen la prioridad más alta para agrupar operaciones, seguidos de potencias, raíces, mult/div y sum/rest.'),(276,1,'¿Qué es un comentario en el código?','Una instrucción que el usuario lee en pantalla.','Texto ignorado por el compilador usado para explicar la lógica a otros humanos.','Un mensaje de error del sistema.','Una variable que guarda opiniones.','B','Los comentarios son vitales para el mantenimiento del código, permitiendo que otros programadores entiendan qué se intentó hacer.'),(277,1,'¿Cuál es la principal diferencia entre una variable y una constante en la ejecución de un programa?','La variable ocupa espacio en memoria RAM y la constante no.','El valor de la variable puede cambiar, mientras que el de la constante permanece inalterado tras su asignación.','Las variables solo almacenan números y las constantes solo texto.','Las constantes se declaran dentro de los ciclos y las variables fuera de ellos.','B','Por definición, una constante protege un valor durante todo el ciclo de vida del programa, mientras que la variable está diseñada para ser reasignada según la lógica del algoritmo.'),(278,1,'¿Qué significa que un algoritmo sea \'Finito\'?','Que debe ser muy delgado al escribirse.','Que debe tener un número determinado de pasos y terminar en algún momento.','Que solo puede procesar números pequeños.','Que no puede ser traducido a otros idiomas.','B','Un proceso que no termina nunca no es un algoritmo funcional, es un error o un proceso infinito.'),(279,1,'En un ciclo \'For\', ¿cuáles son los tres elementos que suelen definirse en la cabecera?','Variable, Condición y Tipo de dato.','Inicialización, Condición e Incremento/paso.','Nombre, Valor y Salida.','Entrada, Proceso y Salida.','B','El ciclo \'For\' agrupa la inicialización del contador, la condición de permanencia y cómo cambia el contador en una sola línea.'),(280,1,'¿Para qué sirve el tipo de dato \'Booleano\'?','Para almacenar números con muchos decimales.','Para representar valores de lógica binaria: Verdadero o Falso.','Para guardar fechas y horas.','Para listas de nombres.','B','Es el tipo de dato más simple y fundamental para la toma de decisiones en condicionales.'),(281,1,'¿Qué tipo de dato devolvería la comparación (10 == \'10\') en un lenguaje con tipado estricto?','Verdadero (True)','Falso (False) o Error','1010','Nulo (Null)','B','En tipado estricto, un Entero y una Cadena de texto son tipos diferentes, por lo que la comparación falla aunque el contenido \'parezca\' igual.'),(282,1,'¿Qué valor booleano resulta de: NOT(5 == 5)?','True','False','5','Null','B','5 == 5 es True. El operador NOT invierte el valor, convirtiéndolo en False.'),(283,2,'¿Cuál es la principal diferencia entre una variable y una constante en la ejecución de un programa?','La variable ocupa espacio en memoria RAM y la constante no.','El valor de la variable puede cambiar, mientras que el de la constante permanece inalterado tras su asignación.','Las variables solo almacenan números y las constantes solo texto.','Las constantes se declaran dentro de los ciclos y las variables fuera de ellos.','B','Por definición, una constante protege un valor durante todo el ciclo de vida del programa, mientras que la variable está diseñada para ser reasignada según la lógica del algoritmo.'),(284,2,'¿Qué tipo es más adecuado para representar cantidades monetarias con precisión exacta en Java básico?','double','float','java.math.BigDecimal','long','C','Para cálculos con precisión decimal exacta se usa BigDecimal; double y float son binarios y pueden introducir errores de redondeo, y long es entero.'),(285,2,'Respecto al alcance (scope), ¿qué ocurre con una variable declarada dentro de un bloque { }?','Solo es accesible dentro de ese bloque.','Permanece accesible en todo el método.','Se convierte en una variable global.','Se elimina en tiempo de compilación y no existe en ejecución.','A','Las variables locales de bloque solo existen y son visibles dentro del bloque donde se declaran.'),(286,2,'¿Cuál es la diferencia principal entre una clase y un objeto en Java?','La clase es una plantilla y el objeto es una instancia concreta creada a partir de ella.','La clase ocupa memoria en el heap y el objeto no.','El objeto define comportamientos y la clase solo datos.','No hay diferencia: ambos términos son sinónimos.','A','Una clase modela la estructura y comportamiento; un objeto es una realización específica con estado propio basada en esa clase.'),(287,2,'¿Qué hace la palabra clave new en Java?','Declara una nueva clase en tiempo de ejecución.','Crea una instancia de una clase y reserva memoria para ella.','Importa un paquete al espacio de nombres actual.','Convierte un tipo primitivo a su wrapper automáticamente.','B','new construye un objeto, invoca su constructor y reserva la memoria necesaria en el heap.'),(288,2,'¿Qué modificador de acceso limita el uso de un miembro exclusivamente a su propia clase?','public','protected','(sin modificador) / package-private','private','D','private restringe el acceso al miembro únicamente dentro de la clase donde se declara.'),(289,2,'En una sentencia switch en Java, si se omite la palabra clave break en un caso, ¿qué ocurre?','Se lanza automáticamente una excepción de tipo IllegalStateException.','El control termina el switch inmediatamente.','Se produce \'fall-through\' y continúa ejecutando el siguiente caso hasta encontrar un break o terminar el switch.','El compilador impide compilar el código.','C','Sin break, el flujo cae al siguiente case (fall-through) ejecutando sus sentencias consecutivas.'),(290,2,'¿Cuál firma es válida para un método que no devuelve valor y recibe un int y un String?','procesar(a, b)','void procesar(int a, String b)','int procesar(void)','function procesar(int a, String b)','B','La sintaxis correcta en Java incluye el tipo de retorno void y la lista de parámetros tipados.'),(291,2,'En un método void, ¿qué implica ejecutar la sentencia return;?','Devuelve null al invocador.','Finaliza el método inmediatamente sin devolver un valor.','Reinicia la ejecución del método desde el inicio.','Devuelve un valor por defecto según el tipo primitivo.','B','En métodos void, return; sirve para salir de forma anticipada sin valor de retorno.'),(292,2,'Para objetos String en Java, ¿cuál es la diferencia entre \'==\' y equals()?','\'==\' compara referencias; equals() compara contenido.','\'==\' compara longitud; equals() compara codificación.','No hay diferencia: ambos comparan contenido.','\'==\' invoca intern() automáticamente.','A','\'==\' verifica si son la misma referencia; equals() determina si las secuencias de caracteres son iguales.'),(293,2,'¿Qué estructura de la biblioteca estándar mantiene orden por índice y permite elementos duplicados?','HashSet','TreeSet','ArrayList','HashMap','C','ArrayList es una lista basada en array dinámico, indexada y admite duplicados; los Set no permiten duplicados.'),(294,2,'¿Cómo se declara y crea un arreglo de 10 enteros en Java?','int a = new int(10);','int[] a = new int[10];','int a[] = {10};','array<int> a = new array<int>(10);','B','La sintaxis correcta para arreglos es tipo[] nombre = new tipo[tamaño];'),(295,2,'¿Cuál es el índice del primer elemento en un arreglo en Java?','1','Depende del tipo del arreglo.','0','-1','C','En Java, los arreglos son indexados desde 0.'),(296,2,'¿Cuándo es más adecuado usar un bucle for-each (for : ) sobre un arreglo o lista?','Cuando necesitas modificar el índice durante la iteración.','Cuando solo lees los elementos en orden y no necesitas el índice.','Cuando necesitas eliminar elementos mientras iteras con seguridad.','Cuando no conoces el tipo de los elementos.','B','El for-each simplifica la lectura secuencial sin exponer el índice ni permitir modificar la colección.'),(297,2,'En POO, la encapsulación se refiere a…','Heredar comportamiento de múltiples clases.','Ocultar el estado interno y exponerlo mediante métodos controlados (getters/setters).','Convertir tipos primitivos en objetos automáticamente.','Compartir variables entre hilos.','B','Encapsular implica restringir el acceso directo a los datos y proveer métodos de acceso para mantener invariantes.'),(298,2,'¿Qué palabra clave impide que una clase sea heredada?','abstract','final','static','sealed','B','final en una clase evita que otras clases la extiendan. (sealed existe en versiones modernas con reglas distintas).'),(299,2,'La sobrecarga de métodos (overloading) en Java se basa en…','Cambiar el nombre del método manteniendo parámetros.','Cambiar la lista de parámetros (número o tipos).','Cambiar solo el tipo de retorno.','Cambiar solo los modificadores de acceso.','B','Dos métodos están sobrecargados si comparten nombre pero difieren en la lista de parámetros.'),(300,2,'La sobrescritura de métodos (overriding) ocurre cuando…','Una clase define múltiples métodos con el mismo nombre y distinta lista de parámetros.','Una subclase define un método con la misma firma y un comportamiento distinto al de la superclase.','Se cambia el tipo de retorno de un método estático.','Se llama a un método privado desde otra clase.','B','Overriding requiere herencia y la misma firma para redefinir el comportamiento.'),(301,2,'¿Cuál es el valor por defecto de una variable de instancia de tipo int si no se inicializa explícitamente?','undefined','0','null','Depende del constructor','B','Los campos de instancia numéricos primitivos se inicializan por defecto a 0; las variables locales deben inicializarse antes de usarse.'),(302,2,'Si no defines ningún constructor en una clase, ¿qué sucede?','El compilador genera un constructor por defecto sin parámetros.','La clase no puede instanciarse.','Se crea un constructor privado automáticamente.','El compilador exige definir al menos uno público.','A','Si no hay constructores declarados, se provee uno por defecto sin argumentos y con visibilidad de la clase.'),(303,2,'¿Qué nivel de acceso tiene un miembro sin modificador explícito (default)?','private','public','protected','package-private (visible solo dentro del mismo paquete)','D','El acceso por defecto en Java es de paquete: visible para clases del mismo paquete.'),(304,2,'¿Qué llamada convierte correctamente un String en un int?','Integer.valueOf(s).intValue()','Integer.parseInt(s)','int.parse(s)','Parse.toInt(s)','B','Integer.parseInt devuelve un primitivo int a partir de un String numérico válido.'),(305,2,'En Java, el valor null representa…','Un número cero de tipo long.','Una referencia que no apunta a ningún objeto.','Un objeto vacío especial con métodos limitados.','Una cadena vacía de longitud cero.','B','null indica ausencia de referencia a objeto; no es una instancia ni una cadena vacía.'),(306,2,'Respecto a String en Java, es correcto afirmar que…','Es mutable para mejorar el rendimiento.','Es inmutable; cualquier modificación crea un nuevo objeto.','Es un tipo primitivo especial del lenguaje.','No se puede usar en colecciones.','B','String es inmutable por diseño, lo que favorece la seguridad y el cacheo de literales.'),(307,2,'¿Cuál es la diferencia práctica entre StringBuilder y StringBuffer?','StringBuilder es sincronizado y más lento; StringBuffer no lo es.','StringBuffer es inmutable y StringBuilder mutable.','StringBuilder no es sincronizado y suele ser más rápido en un solo hilo; StringBuffer es sincronizado.','No hay diferencias: son equivalentes.','C','StringBuffer sincroniza operaciones (útil en concurrencia), StringBuilder evita esa sobrecarga en contextos de un solo hilo.'),(308,2,'¿Cuál de las siguientes es una excepción verificada (checked) en Java?','NullPointerException','ArrayIndexOutOfBoundsException','IOException','ArithmeticException','C','IOException es checked y debe declararse o manejarse; las otras son unchecked (RuntimeException).'),(309,2,'¿Qué bucle es más adecuado cuando conoces de antemano el número exacto de iteraciones?','for clásico (for inicialización; condición; actualización)','while','do-while','foreach','A','El for clásico expresa naturalmente conteos definidos con un índice.'),(310,2,'El operador ternario (cond ? a : b) sirve para…','Crear dos hilos y escoger cuál corre.','Evaluar una condición y seleccionar entre dos expresiones.','Concatenar cadenas de forma perezosa.','Generar excepciones personalizadas.','B','El operador condicional devuelve a si la condición es verdadera o b en caso contrario.'),(311,2,'¿Cuál es el resultado de 5 / 2 cuando ambos operandos son int en Java?','2.5','2','3','Depende de la JVM','B','La división entre enteros descarta la parte fraccionaria, resultando 2.'),(312,2,'Para comparar por igualdad lógica dos instancias de una clase Persona en una lista, lo más apropiado es…','Usar \'==\' para comparar campos uno a uno.','Sobrescribir equals y hashCode de forma coherente en Persona.','Convertir las personas a String y comparar las cadenas.','Utilizar System.identityHashCode para comparar.','B','equals/hashCode permiten definir igualdad lógica y comportarse correctamente en colecciones.'),(313,2,'La palabra clave this en un método de instancia hace referencia a…','La clase actual como tipo.','El paquete donde se ubica la clase.','La instancia actual del objeto que ejecuta el método.','La superclase inmediata.','C','this es la referencia al objeto receptor en el contexto actual.'),(314,2,'La palabra clave super permite…','Acceder a miembros estáticos sin calificación.','Referirse a miembros de la superclase o invocar su constructor.','Crear objetos sin usar new.','Elevar privilegios de acceso a private.','B','super refiere a la superclase para acceder a sus miembros no privados o llamar a su constructor.'),(315,2,'¿Cómo se declara correctamente una constante pública de clase en Java?','public const int MAX = 10;','public static final int MAX = 10;','public final int MAX = 10;','public static const int MAX = 10;','B','Las constantes de clase se declaran con static final; no existe la palabra clave const en Java.'),(316,2,'Si necesitas acceso rápido por índice y sueles añadir elementos al final, ¿qué implementación de List conviene más?','LinkedList','ArrayList','Vector','Stack','B','ArrayList ofrece acceso O(1) promedio por índice y apéndices amortizados eficientes; LinkedList favorece inserciones/remociones en medio.'),(317,2,'Dado un método calcular(int x), ¿cuál de las siguientes es una sobrecarga válida?','int calcular(int y) throws Exception','double calcular(int x)','void calcular()','calcular(int x)','C','Para sobrecargar se debe cambiar la lista de parámetros. Cambiar solo el tipo de retorno (opción B) no sobrecarga; \'throws\' no afecta la firma para overloading.'),(318,2,'¿Cuál de las siguientes declaraciones crea un arreglo para tres referencias de Persona?','Persona personas = new Persona[3];','Persona[] personas = new Persona[3];','new Persona[3] personas;','Persona[3] personas = new Persona[];','B','La forma correcta es Tipo[] nombre = new Tipo[tamaño]; esto crea el arreglo de referencias.'),(319,2,'Tras ejecutar Persona[] p = new Persona[3]; ¿qué hay en p[0]?','Una instancia Persona creada con el constructor por defecto.','Una referencia null.','Una referencia no inicializada que causa error de compilación.','Un objeto vacío con valores por defecto.','B','El arreglo de referencias contiene null hasta que se asigne explícitamente new Persona() a cada posición.'),(320,2,'Respecto a switch en versiones modernas de Java, ¿es posible usar String como expresión?','Sí, se puede usar String y se compara por contenido.','No, solo se permiten tipos numéricos primitivos.','Sí, pero únicamente si el String está internado manualmente.','Solo en clases abstractas.','A','Desde Java 7 se pueden usar String en switch, comparando según equals().'),(321,2,'¿Qué modificador indica que un método pertenece a la clase y no a la instancia?','final','static','abstract','native','B','static asocia el método a la clase; puede invocarse sin crear un objeto.'),(322,2,'Si necesitas una colección que evite duplicados sin importar el orden, ¿cuál usarías?','ArrayList','LinkedList','HashSet','PriorityQueue','C','Un Set (como HashSet) no permite duplicados y no garantiza un orden específico.'),(323,1,'Si edad = 17 y permisoEspecial = True, ¿qué resultado tiene la condición (edad >= 18) OR (permisoEspecial == True)?','True','False','Error de sintaxis','Depende del lenguaje, nunca se puede saber','A','En un OR basta con que una condición sea verdadera. Aunque edad >= 18 es falso, permisoEspecial == True es verdadero, así que toda la condición resulta verdadera.'),(324,1,'¿Cuál es el resultado de la expresión: True OR False AND False (asumiendo que AND se evalúa antes que OR)?','True','False','Error de sintaxis','No se puede evaluar sin un ciclo','A','Primero se evalúa False AND False = False. Luego True OR False = True. La prioridad de operadores influye en el resultado.'),(325,1,'Si quieres intercambiar los valores de a y b sin perder ninguno, ¿cuál enfoque es el más seguro en un algoritmo básico?','Asignar a = b y luego b = a, sin usar nada más.','Asignar b = a y luego a = b, sin usar nada más.','Usar una variable temporal: temp = a; a = b; b = temp.','Sumar los valores: a = a + b; b = a + b; a = a - b.','C','La variable temporal conserva el valor original de a mientras se reasigna, evitando que uno de los valores se sobrescriba antes de tiempo.'),(326,1,'¿Cuántas veces se ejecuta el cuerpo de un ciclo si inicia en i = 1 y repite mientras i < 5, aumentando i en 1 cada vez?','3 veces','4 veces','5 veces','Es un bucle infinito','B','Con i < 5, las iteraciones ocurren para i = 1, 2, 3 y 4. Cuando i llega a 5, la condición deja de cumplirse.'),(327,1,'En una división, ¿cuál afirmación describe mejor por qué a veces 5 / 2 da 2 y otras veces da 2.5?','Siempre da 2.5, porque toda división produce decimales.','Depende de si se usan números enteros o decimales: con enteros puede truncar y con decimales conserva la parte decimal.','Siempre da 2, porque el residuo se elimina en cualquier lenguaje.','Da error, porque no se puede dividir 5 entre 2.','B','La forma en que se calcula la división puede depender del tipo de dato. Con enteros, algunos lenguajes realizan división entera (truncada).'),(328,1,'Si i inicia en 0 y se ejecuta un ciclo mientras i < 10, pero dentro del ciclo nunca se cambia i, ¿qué es lo más probable que ocurra?','El ciclo se ejecuta exactamente 10 veces.','El ciclo se ejecuta 9 veces y se detiene.','El ciclo puede volverse infinito porque la condición nunca cambia.','El programa compila pero siempre salta el ciclo.','C','Si i nunca se actualiza, seguirá siendo 0 y la condición i < 10 permanecerá verdadera, causando un bucle infinito.'),(329,1,'Si la regla es: si nota >= 3.0 entonces \'Aprueba\', en caso contrario \'Reprueba\', ¿qué sucede cuando nota = 3.0?','Aprueba','Reprueba','Da error porque 3.0 no es válido','Se salta la condición y no muestra nada','A','El operador >= incluye el límite. Si nota es exactamente 3.0, la condición se cumple y se ejecuta la rama de aprobación.'),(330,1,'Si necesitas guardar el resultado de 7 / 2 como 3.5 (con decimales), ¿qué tipo de dato es más adecuado para la variable resultado?','Entero (Integer)','Flotante/Decimal (Float/Double)','Booleano (Boolean)','Carácter (Char)','B','Un tipo flotante permite representar valores con parte decimal. Con enteros, muchas veces la división se trunca y se pierde la parte decimal.'),(331,1,'En muchos lenguajes, ¿qué diferencia práctica hay entre usar \'=\' y \'==\' dentro de una condición?','\'=\' compara dos valores y \'==\' asigna un valor a una variable.','\'=\' se usa para asignar un valor, mientras que \'==\' se usa para comparar si dos valores son iguales.','Ambos operadores hacen exactamente lo mismo dentro de una condición.','\'==\' solo funciona con números y \'=\' solo con texto.','B','En la mayoría de lenguajes, \'=\' realiza asignación y \'==\' realiza comparación. Confundirlos suele causar errores de lógica o de compilación según el lenguaje.'),(332,1,'En un ciclo, ¿qué efecto tiene la instrucción \'continue\' (en los lenguajes que la soportan)?','Finaliza el ciclo por completo y sale de él.','Salta al inicio de la siguiente iteración, omitiendo el resto de instrucciones de la iteración actual.','Repite la misma iteración sin volver a evaluar la condición.','Declara una variable para continuar el programa.','B','\'continue\' no termina el ciclo; solo omite lo que falta de la iteración actual y vuelve al control del ciclo para seguir con la siguiente.'),(333,27,'¿Cuál es una estrategia válida para @GeneratedValue?','GenerationType.NONE','GenerationType.IDENTITY','GenerationType.CUSTOM obligatoria','GenerationType.AUTO_ONLY','B','IDENTITY delega en columnas autoincrementales; también existen SEQUENCE, TABLE y AUTO.'),(334,27,'En herencia, SINGLE_TABLE se caracteriza por…','Evitar JOINS a costa de columnas nulas y un discriminador','Crear una tabla por clase concreta','Usar siempre FK hacia la superclase','Exigir @Embeddable','A','SINGLE_TABLE usa una sola tabla con columna discriminadora; es veloz en lecturas pero puede tener muchas columnas nulas.'),(335,27,'Para paginar con Spring Data JPA, un método típico retorna…','List<T> y recibe int page, int size','Page<T> o Slice<T> y recibe Pageable','Iterator<T> y recibe Sort','Stream<T> y recibe int limit','B','Los repositorios pueden aceptar Pageable y devolver Page o Slice con metadatos (totales, página, etc.).'),(336,27,'En @Query, ¿qué ventaja aporta SpEL (por ejemplo :#{#param})?','Permite evaluar expresiones y acceder a propiedades de parámetros complejos','Solo sirve para sumar enteros','Deshabilita parámetros nombrados','Obliga a SQL nativo','A','SpEL habilita expresiones dinámicas y acceso a subpropiedades de argumentos para construir filtros más expresivos.'),(337,27,'¿Para qué sirve un AttributeConverter<T, Y> en JPA?','Para interceptar todas las queries','Para generar PKs','Para convertir atributos entre representación Java y columna persistida','Para implementar locking pesimista','C','Un AttributeConverter transforma valores entre el modelo y la BD (en ambos sentidos) sin cambiar el mapeo de la entidad.'),(338,27,'¿Qué hace @EntityGraph en un método de repositorio?','Define validaciones Bean Validation','Activa caché de segundo nivel','Especifica un grafo de entidades para controlar la carga de asociaciones en esa consulta','Impone ordenación por defecto','C','@EntityGraph permite ajustar selectivamente qué relaciones se cargan (atributos) sin modificar el mapeo global.'),(339,27,'Para mapear un enum de forma robusta ante reordenamientos, conviene…','Usar @Enumerated(EnumType.ORDINAL)','Persistir su hashCode()','Usar @Enumerated(EnumType.STRING)','Persistir su ordinal + 1','C','STRING guarda el nombre del enum, estable ante cambios de orden; ORDINAL es sensible a reordenamientos.'),(340,27,'Con @Accessors(chain = true) en Lombok, los setters…','Devuelven void','Se desactivan','Devuelven \'this\' permitiendo encadenamiento de llamadas','Se vuelven estáticos','C','@Accessors(chain=true) hace que los setters retornen la instancia, permitiendo patrón de encadenamiento (fluido).'),(341,27,'¿Qué permite pasar parámetros nombrados a @Query?',':1, :2, :3','?0 exclusivamente','@Param(\"nombre\") para mapear argumentos a :nombre','SpEL no es compatible','C','@Param vincula parámetros del método a los marcadores :nombre en la consulta; también es posible usar SpEL en algunos contextos.'),(342,27,'¿Qué hace clear() en EntityManager?','Hace flush y cierra la sesión','Reinicia el contador @Version','Desasocia todas las entidades (todas pasan a \'detached\')','Elimina la caché de segundo nivel','C','clear vacía el contexto de persistencia: ninguna entidad permanece gestionada tras la llamada.'),(343,27,'¿Qué es correcto sobre la caché de segundo nivel (2LC) en Hibernate?','Es obligatoria y por sesión','Es opcional y compartida entre sesiones; requiere proveedor (Ehcache/Infinispan)','Solo cachea consultas nativas','Siempre invalida en cada flush','B','El 2LC es opcional, compartido y configurable por regiones/estrategias; no sustituye la caché de primer nivel.'),(344,27,'¿Cuál es el efecto de detach(e) sobre una entidad?','Pasa a estado \'removed\' y se ejecuta DELETE inmediatamente','Se bloquea pesimistamente la fila','Deja de ser gestionada; cambios posteriores ya no se sincronizan','Se vacía la caché de segundo nivel','C','detach saca la entidad del contexto: no hay dirty checking posterior, aunque la instancia siga existiendo en memoria.'),(345,27,'En JPA, una entidad en estado \'managed\' significa que…','Está anexada al contexto de persistencia y sus cambios serán sincronizados en flush','Es inmutable y jamás puede cambiar de estado','Se ha eliminado físicamente de la base de datos','Siempre utiliza lazy loading para todas sus relaciones','A','Una entidad \'managed\' es rastreada por el EntityManager; el dirty checking detecta cambios y los sincroniza en el próximo flush/commit.'),(346,27,'En Spring Data JPA, ¿qué hace @Modifying(clearAutomatically = true)?','Cierra el EntityManager','Limpia el contexto tras ejecutar la consulta DML para evitar estados obsoletos','Desactiva la transacción','Convierte la consulta en nativa','B','clearAutomatically limpia el contexto después de ejecutar una actualización/borrado, evitando ver datos stale en entidades gestionadas.'),(347,27,'¿Qué propósito tiene @Version en una entidad?','Generar claves primarias','Configurar auditoría automática','Implementar locking optimista y detectar escrituras concurrentes','Obligar a EAGER en relaciones','C','@Version mantiene un contador o timestamp para detectar conflictos y lanzar OptimisticLockException.'),(348,27,'Para ejecutar una actualización/borrado con @Query en Spring Data JPA se requiere…','Nada adicional','@Modifying y gestión transaccional apropiada','@Transactional(readOnly=true)','@Lock(PESSIMISTIC_WRITE)','B','Las queries DML necesitan @Modifying y ejecutarse dentro de una transacción.'),(349,27,'¿Qué hace @ToString.Exclude en Lombok?','Impide imprimir el campo en logs del framework','Elimina la serialización JSON','Excluye el campo del toString generado para evitar recursión o datos sensibles','Lo marca como transient','C','@ToString.Exclude evita que el campo aparezca en la representación de cadena generada (útil con relaciones bidireccionales).'),(350,27,'¿Qué diferencia hay entre @Embedded y @Embeddable?','No hay diferencia','@Embedded se coloca donde se usa el valor; @Embeddable en la clase de valor','@Embeddable crea tabla separada','@Embedded define una FK','B','@Embeddable marca un tipo incrustable; @Embedded lo inserta como parte de la entidad en la misma tabla.'),(351,27,'La excepción LazyInitializationException suele ocurrir cuando…','Se accede a una asociación LAZY fuera del alcance de la sesión/transacción','Se ejecuta un ORDER BY','Se usa @Version','Se hace flush','A','Fuera de sesión activa, el proveedor no puede inicializar el proxy/colección, lanzando la excepción.'),(352,27,'Extender JpaRepository<Entity, ID> aporta…','Eliminación de transacciones','Operaciones adicionales como paginación/sorting y métodos utilitarios','Soporte exclusivo para SQL nativo','Proxies de caché automáticos','B','JpaRepository agrega Page, Sort y utilitarios de JPA encima de CrudRepository.'),(353,27,'¿Qué implica flush() en JPA/Hibernate?','Cierra la sesión actual','Borra la caché de segundo nivel','Sincroniza el contexto con la BD emitiendo SQL pendiente (INSERT/UPDATE/DELETE)','Marca todas las entidades como \'detached\'','C','flush envía a la base de datos las operaciones acumuladas para mantener consistencia; no cierra el EntityManager ni la transacción.'),(354,27,'Los métodos derivados como findByEmailAndEstadoTrue generan…','Excepciones siempre','Solo validaciones, no consultas','Consultas basadas en el nombre del método y las convenciones de palabras clave','Índices automáticos','C','Spring Data parsea el nombre del método y construye la query (derivation) según palabras clave (And, Or, Between, Containing, etc.).'),(355,27,'¿Qué genera @Getter/@Setter de Lombok por defecto?','Getters y setters públicos para campos no estáticos','Constructores all-args y no-args','equals/hashCode y toString','Un builder completo','A','@Getter/@Setter crean accesores mutadores para cada campo; se puede cambiar el AccessLevel y excluir campos puntuales.'),(356,27,'¿Por qué es problemático usar @Data en entidades JPA complejas?','Porque impide serialización JSON','Porque equals/hashCode y toString pueden incluir relaciones perezosas causando cargas o ciclos','Porque elimina @Entity','Porque bloquea herencia','B','@Data incluye equals/hashCode/toString; en entidades con asociaciones LAZY puede provocar N+1 o recursión. Es mejor personalizar.'),(357,27,'¿Qué hace refresh(e) en JPA?','Aplica un merge parcial solo a relaciones LAZY','Descarta cambios en memoria y recarga el estado actual desde la base de datos','Inicializa todas las colecciones LAZY','Convierte la entidad en \'detached\'','B','refresh fuerza a recuperar el estado de la BD, sobrescribiendo el estado actual de la entidad gestionada.'),(358,27,'¿Qué LockModeType usa el campo @Version para detectar conflictos?','PESSIMISTIC_WRITE','OPTIMISTIC u OPTIMISTIC_FORCE_INCREMENT','PESSIMISTIC_READ','NONE','B','Los modos optimistas se basan en @Version; los pesimistas bloquean filas en la BD y requieren transacciones activas.'),(359,27,'¿Qué operación JPA transiciona una entidad \'transient\' a \'managed\'?','merge()','persist()','detach()','refresh()','B','persist() hace que una instancia nueva (transient) quede gestionada; merge() copia el estado de una instancia \'detached\' a una administrada.'),(360,27,'¿Qué evento de ciclo de vida se invoca antes de insertar por primera vez una entidad?','@PostPersist','@PreUpdate','@PrePersist','@PostLoad','C','@PrePersist se ejecuta justo antes de que el proveedor inserte la entidad; @PostPersist ocurre después del INSERT.'),(361,27,'@MapsId se utiliza para…','Mapear un id compuesto en memoria sin columnas','Evitar usar @Id','Compartir la clave primaria del hijo con la del padre en relaciones como OneToOne','Forzar a usar TABLE inheritance','C','@MapsId hace que el valor de la PK provenga de otra asociación, útil en dependencias fuertes (FK = PK).'),(362,27,'En Criteria API, una ventaja frente a JPQL literal es…','Mayor rendimiento garantizado','Construcción typesafe y composición dinámica de filtros','Menos JOINS siempre','Evitar validaciones Bean Validation','B','Criteria facilita consultas dinámicas con tipos estáticos; el rendimiento depende del SQL resultante, no del estilo.'),(363,27,'¿Qué hace @Lob?','Convierte un String en PK','Indica que el campo se mapea a un tipo grande (BLOB/CLOB)','Evita el fetch LAZY','Crea un índice automático','B','@Lob mapea datos grandes como binarios o de texto largo; el tipo concreto depende del proveedor y del RDBMS.'),(364,27,'Con hbm2ddl.auto=validate, ¿qué sucede al arrancar?','Se eliminan y recrean tablas','Se intenta ajustar el esquema con ALTER','No hace nada en absoluto','Se verifica el esquema contra el mapeo y falla si hay inconsistencias','D','\'validate\' comprueba que el esquema existente sea compatible con los mapeos; no crea ni modifica tablas.'),(365,27,'¿Qué hace un fetch join en JPQL?','Obliga paginación','Carga una asociación en la misma consulta para evitar N+1','Convierte LAZY en EAGER permanentemente','Equivale a un CROSS JOIN','B','El fetch join recupera la entidad y sus asociaciones necesarias en una sola consulta, mitigando N+1.'),(366,27,'¿Cuál es el efecto de FlushModeType.COMMIT?','Hace flush antes de cada query','Cierra el EntityManager automáticamente','Difere el flush hasta el commit, evitando sincronizar antes de lecturas','Elimina el dirty checking','C','COMMIT aplaza la sincronización hasta el commit de la transacción, útil para rendimiento/control de lecturas.'),(367,27,'¿Qué distingue JPQL de SQL nativo?','JPQL consulta entidades y atributos; el proveedor la traduce a SQL','JPQL opera directamente sobre tablas y columnas','JPQL solo sirve para inserts','No hay diferencia','A','JPQL trabaja sobre el modelo de entidades; es independiente del esquema físico y el dialecto genera el SQL correspondiente.'),(368,27,'¿Qué ventaja aporta un EntityGraph?','Crea índices automáticamente','Define políticas de carga para atributos, seleccionando qué asociaciones traer en una consulta','Impone EAGER por defecto','Evita transacciones','B','Los EntityGraph permiten declarar rutas de carga (fetch plans) sin alterar los mapeos, mejorando control y rendimiento.'),(369,27,'¿Y una proyección DTO por constructor?','Requiere entityManager.join()','Usa un constructor explícito en JPQL (select new paquete.Dto(a,b,c)) para mapear resultados','Solo con SQL nativo','No existe en Spring Data','B','JPQL admite instanciación de clases DTO con \'select new ...\'; Spring Data puede mapear esos resultados al DTO.'),(370,27,'¿Qué describe correctamente el \'dirty checking\' de Hibernate?','Es la creación de índices en la base de datos','Es la detección automática de cambios en entidades gestionadas para sincronizarlos en flush','Es el borrado de cachés al cerrar la sesión','Es la validación Bean Validation antes del commit','B','Hibernate guarda instantáneas del estado original y emite UPDATE/DELETE al detectar cambios al hacer flush/commit.'),(371,27,'¿Por qué no es recomendable usar @Value (Lombok) en una entidad JPA?','Porque vuelve la clase final e inmutable, dificultando proxies y requisitos de constructor sin-args','Porque elimina @Id','Porque obliga a LAZY','Porque deshabilita Bean Validation','A','@Value marca la clase como final e inmutable; los proxies de Hibernate y el constructor sin-args requerido por JPA pueden verse afectados.'),(372,27,'¿Qué diferencia hay entre @RequiredArgsConstructor y @AllArgsConstructor en Lombok?','No hay diferencia','Required genera constructor con campos final/@NonNull; All incluye todos los campos','All crea solo sin-args','Required incluye setters','B','@RequiredArgsConstructor exige solo los campos esenciales (final/@NonNull); @AllArgsConstructor incluye todos los atributos.'),(373,27,'¿Qué hace @Converter(autoApply = true)?','Desactiva todos los conversores','Aplica el AttributeConverter a todos los atributos del tipo de forma automática','Obliga a usar @Enumerated','Solo afecta a IDs','B','autoApply hace que el conversor se use globalmente para el tipo declarado sin anotar cada atributo individual.'),(374,27,'La caché de primer nivel (nivel 1) en Hibernate/JPA…','Es compartida entre sesiones y nodos','Requiere Ehcache o Infinispan','Está asociada a la sesión/EntityManager y es obligatoria','Solo cachea queries nativas','C','El primer nivel vive dentro de la sesión/EntityManager y asegura identidad por sesión; no es distribuido.'),(375,27,'¿Qué permite @Query(nativeQuery = true) en repositorios?','Usar JPQL con funciones del dialecto','Solo ejecutar DDL','Ejecutar SQL nativo y mapear resultados según la firma (entidad, proyección, DTO)','Evitar parámetros','C','nativeQuery=true ejecuta SQL propio del RDBMS; los resultados pueden mapearse a entidades o proyecciones compatibles.'),(376,27,'¿Cuál es el modo por defecto de FetchType en @ManyToOne según JPA?','LAZY','EAGER','DEPENDS','MANUAL','B','La especificación establece EAGER por defecto para ManyToOne/OneToOne y LAZY para OneToMany/ManyToMany (aunque en práctica se prefiere LAZY explícito).'),(377,27,'¿Cómo se definen consultas JPQL personalizadas en repositorios?','Con @Query sobre el método','Con @Sql directamente en la entidad','Solo mediante Specifications','No es posible','A','@Query permite declarar JPQL (y también nativas con nativeQuery=true) asociadas a métodos del repositorio.'),(378,27,'Diferencia entre @ElementCollection y una relación @OneToMany a entidad:','@ElementCollection persiste valores embebidos o tipos básicos sin identidad propia','@ElementCollection siempre crea FK compuesta','OneToMany no puede usar LAZY','No hay diferencias prácticas','A','@ElementCollection almacena colecciones de valores (embeddables/básicos); OneToMany se usa para entidades con identidad.'),(379,27,'¿Qué hace @BatchSize en Hibernate?','Evita la paginación','Cambia el aislamiento','Indica el tamaño de lote para cargar colecciones o entidades relacionadas, reduciendo viajes a BD','Obliga EAGER','C','@BatchSize permite recuperar múltiples registros relacionados en lotes para mitigar N+1 sin fetch join.'),(380,27,'¿Para qué sirve @EnableJpaRepositories en configuración clásica?','Para configurar Boot Actuator','Para habilitar escaneo de interfaces de repositorio y crear proxies','Para inicializar migraciones','Para generar entidades automáticamente','B','@EnableJpaRepositories habilita la detección de repositorios y su proxying; en Boot suele activarse por autoconfiguración, pero no es requerido aquí.'),(381,27,'En una relación bidireccional @OneToMany, ¿dónde se usa \'mappedBy\'?','En el lado propietario','En ambos lados','En el lado inverso que no posee la relación','Nunca se usa en JPA','C','\'mappedBy\' declara el lado no propietario; el propietario define la FK con @JoinColumn o @JoinTable.'),(382,27,'¿Qué anotación marca el identificador primario de una entidad?','@Id','@PrimaryKey','@Identifier','@Key','A','@Id designa el atributo PK; puede combinarse con @GeneratedValue para generación automática.'),(383,27,'¿Cuál es el efecto de @OrderBy(\"campo ASC\") sobre una colección JPA?','Cambia el orden físico de inserción en BD','Ordena la colección en memoria sin afectar consultas','Convierte la colección en Set','Inserta un ORDER BY en la carga de la colección','D','@OrderBy agrega ORDER BY en la consulta que inicializa la colección, afectando cómo se recuperan los elementos.'),(384,27,'¿Cuándo conviene @JoinTable en asociaciones?','Para forzar EAGER','Cuando no se desea una FK directa y se usa una tabla intermedia','Para claves naturales','Para evitar @ManyToMany','B','@JoinTable modela relaciones a través de una tabla de asociación (típico en ManyToMany).'),(385,27,'¿Qué ocurre si un método derivado es ambiguo (p. ej., findByNameOrNameLike)?','Se elige arbitrariamente una semántica','Spring Data lanza error de derivación por ambigüedad o requiere @Query','Se ignora el sufijo','Se configura automáticamente','B','Cuando el parser no puede desambiguar el nombre del método, se rechaza o se recomienda proveer @Query explícita.'),(386,27,'¿Cómo se aplica ordenación?','Solo con @OrderBy en entidades','Pasando un objeto Sort a métodos del repositorio o usando Pageable que incluye Sort','No es posible con Spring Data','Exclusivamente con SQL nativo','B','Spring Data JPA acepta Sort o Pageable (que integra Sort) para ordenar resultados en ejecución.'),(387,27,'¿Qué interfaz base provee operaciones CRUD en Spring Data JPA?','CrudRepository','JpaTemplate','JdbcRepository','RepositoryManager','A','CrudRepository define operaciones CRUD genéricas; JpaRepository las extiende con más utilidades (paginación, flush, etc.).'),(388,27,'Con @Lock en repositorios Spring Data JPA puedes…','Definir estrategias de bloqueo (OPTIMISTIC/PESSIMISTIC) a nivel de método','Desactivar transacciones','Cambiar el dialecto','Eliminar la caché','A','@Lock permite aplicar LockModeType a una consulta concreta del repositorio.'),(389,27,'¿Qué sucede al invocar remove(e) sobre una entidad \'managed\'?','Se borra inmediatamente de la BD','Se marca para eliminación y el DELETE ocurre en flush/commit','Se convierte en \'detached\' sin borrar','Se reinicia el contador @Version','B','remove pone la entidad en estado \'removed\'; el SQL se ejecuta al sincronizar (flush/commit).'),(390,27,'¿Qué hace orphanRemoval=true en una asociación?','Evita eliminar hijos con FK nula','Elimina entidades hijas que quedan desasociadas del padre','Convierte el fetch en EAGER','Impide cascadas de persistencia','B','orphanRemoval borra registros huérfanos cuando se quitan de la colección o se rompe la relación con el padre.'),(391,27,'¿Qué es una proyección por interfaz en Spring Data?','Una entidad completa con menos columnas','Un DTO imposible de mapear automáticamente','Una interfaz que define getters y a la que se mapean campos seleccionados de la consulta','Una vista materializada','C','Las proyecciones por interfaz permiten seleccionar campos específicos y mapearlos a getters sin instanciar la entidad completa.'),(392,27,'¿Qué diferencia hay entre @EmbeddedId y @IdClass?','No hay diferencia','@EmbeddedId usa una clase embebida como PK; @IdClass referencia una clase externa para los campos de PK','@IdClass obliga a secuencias','@EmbeddedId no soporta relaciones','B','@EmbeddedId encapsula la PK en un tipo embebido; @IdClass define una clase clave cuyos campos deben existir en la entidad.'),(394,1,'¿Qué problema describe mejor un error de \'off-by-one\' (desfase de uno) en ciclos?','El ciclo nunca inicia.','El ciclo itera una vez más o una vez menos de lo esperado por usar < en lugar de <= (o viceversa).','El ciclo no modifica su contador.','El ciclo se ejecuta infinitamente por una condición siempre verdadera.','B','El error de desfase de uno ocurre por límites incorrectos en la condición del ciclo.'),(395,1,'En una cadena de \'si - sino si - sino\', ¿cuándo se ejecuta el bloque \'sino\'?','Siempre, después del primer \'si\'.','Solo si todas las condiciones anteriores fueron falsas.','Cuando la primera condición es verdadera.','Cuando alguna condición intermedia es verdadera.','B','\'sino\' actúa como caso por defecto: se ejecuta si ninguna condición previa fue verdadera.'),(396,1,'Se requiere contar cuántos números negativos hay en una lista. ¿Cuál patrón es más adecuado?','Un acumulador que sume los valores negativos.','Un contador que aumente en 1 cada vez que un elemento sea negativo.','Un ciclo sin cuerpo y solo una condición.','Un \'según sea\' con todos los números posibles.','B','Para contar elementos que cumplen una condición se utiliza un contador, no un acumulador.'),(397,1,'Se desea encontrar el primer número mayor que 0 en una lista. ¿Qué control de flujo es más adecuado?','Seguir recorriendo toda la lista aunque ya se encontró.','Usar un ciclo con una bandera (encontrado) y romper (break) al hallarlo.','Usar únicamente condicionales anidados sin ciclos.','Sumar todos los números y dividir por la longitud.','B','Una bandera o una interrupción temprana optimiza el recorrido al detenerse cuando se cumple el objetivo.'),(398,1,'Al calcular el promedio de N valores ingresados por el usuario, ¿qué estructura es más apropiada si se conoce N de antemano?','Un ciclo \'para\' con N iteraciones.','Un \'mientras verdadero\' sin condición de salida.','Un \'según\' con N casos.','Solo condicionales, sin ciclos.','A','Cuando se conoce el número fijo de repeticiones, un \'para\' es directo y claro.'),(399,1,'Si n = 1234 y se hace: contar = 0; mientras n > 0: n = n / 10 (entera); contar = contar + 1. ¿Qué valor tendrá \'contar\'?','2','3','4','5','C','Se eliminan dígitos enteros sucesivamente: 1234→123→12→1→0. Se cuentan 4 iteraciones.'),(400,1,'Para validar una contraseña no vacía, ¿cuál condición es adecuada?','si longitud(contraseña) > 0','si contraseña == \'\' o longitud(contraseña) > 0','si longitud(contraseña) >= -1','si longitud(contraseña) < 0','A','Una contraseña no vacía implica longitud estrictamente mayor que 0.'),(401,1,'¿Cuál es la condición correcta para repetir la lectura de una nota hasta que esté en el rango [0, 5]?','mientras nota < 0 y nota > 5','mientras nota <= 0 o nota >= 5','mientras nota < 0 o nota > 5','mientras nota == 0 y nota == 5','C','Se repite mientras esté fuera del rango; es decir, si es menor que 0 o mayor que 5.'),(402,1,'¿Qué sucede con la variable \'suma\' en: suma = 0; para i desde 1 hasta 4: si i == 3 entonces continuar; suma = suma + i?','suma = 10','suma = 7','suma = 6','suma = 3','B','Se omite i=3 por \'continuar\'; se suman 1, 2 y 4 → 7.'),(403,1,'Dada la expresión lógica: NOT(True AND False) OR False, ¿cuál es el resultado?','True','False','Indeterminado','Depende del lenguaje','A','True AND False = False; NOT(False) = True; True OR False = True.'),(404,1,'En un \'según sea\' (switch) con casos 1, 2, 3 y un caso por defecto, si la variable vale 4, ¿qué bloque se ejecuta?','El caso 1','El caso 2','El caso 3','El caso por defecto','D','Al no coincidir 4 con ningún caso explícito, se ejecuta el bloque por defecto.'),(405,1,'¿Qué valor final tiene \'i\' después de: i = 0; mientras i < 3: i = i + 1?','0','1','2','3','D','El ciclo ejecuta i=1, i=2, i=3; al llegar a 3 termina, quedando i en 3.'),(406,1,'En un ciclo anidado (dos niveles), ¿qué efecto tiene \'romper\' (break) en el ciclo interno?','Detiene ambos ciclos siempre.','Solo detiene el ciclo interno; el externo continúa con su siguiente iteración.','No tiene efecto en ningún ciclo.','Reinicia el programa desde el inicio.','B','El \'break\' afecta el ciclo donde se ejecuta; el externo sigue según su propia condición.'),(407,1,'En pseudocódigo: contador = 0; para i desde 1 hasta 5 hacer: si i % 2 == 0 entonces contador = contador + 1. ¿Cuál es el valor final de contador?','1','2','3','4','B','Los pares entre 1 y 5 son 2 y 4; se cuentan 2 valores.'),(408,1,'¿Cuál es el objetivo de usar una variable bandera (flag) en un algoritmo?','Controlar el formato de impresión.','Recordar si cierto evento/condición ya ocurrió para tomar decisiones posteriores.','Incrementar un contador automáticamente.','Forzar la salida de todos los ciclos.','B','Las banderas almacenan estados lógicos (verdadero/falso) para guiar el flujo según eventos previos.'),(409,1,'Si un ciclo \'repetir hasta\' finaliza cuando suma >= 100, ¿qué característica tiene su condición de parada?','Se evalúa al inicio del ciclo.','Se evalúa al final, por lo que el cuerpo se ejecuta al menos una vez.','Depende del compilador.','No tiene condición de parada.','B','\'Repetir...hasta\' comprueba la condición al final, garantizando al menos una ejecución.'),(410,1,'En pseudocódigo, si i empieza en 1 y mientras i <= 5 haces i = i + 2, ¿cuántas veces se ejecuta el cuerpo del ciclo?','2 veces','3 veces','4 veces','5 veces','B','Los valores de i serán 1, 3 y 5. Se ejecuta 3 veces antes de que i pase a 7 y falle la condición.'),(411,1,'¿Cuál opción representa correctamente la negación de (A > 0 AND B <= 10) usando las leyes de De Morgan?','A <= 0 AND B > 10','A <= 0 OR B > 10','A > 0 OR B <= 10','NOT(A > 0) AND NOT(B <= 10)','B','NOT(X AND Y) equivale a NOT X OR NOT Y: NOT(A>0) es A<=0; NOT(B<=10) es B>10.'),(412,1,'Si se ejecuta: suma = 0; para i desde 2 hasta 10 paso 2: suma = suma + i. ¿Cuál es el valor de suma?','20','24','30','32','C','Se suman 2+4+6+8+10 = 30.'),(413,1,'¿Cuál es la forma correcta de verificar que un número N está entre 1 y 100 (incluidos)?','si N > 1 y N < 100','si N >= 1 y N <= 100','si N == 1 o N == 100','si N < 1 o N > 100','B','Incluir los límites requiere usar >= y <= en la condición compuesta.'),(414,1,'Si total empieza en 0 y se lee precio hasta que sea -1 (sentinela), sumando cada precio válido, ¿qué condición del ciclo es correcta?','mientras precio == -1','mientras precio != -1','repetir hasta precio != -1','siempre','B','Se itera mientras el valor leído no sea el sentinela; cuando es -1, se detiene.'),(500,28,'¿Qué ventaja describe mejor CSS Grid frente a Flexbox?','Grid es mejor para layouts bidimensionales (filas y columnas); Flexbox es más unidimensional','Grid solo funciona en móviles','Flexbox permite filas y columnas y Grid no','Grid reemplaza completamente media queries','A','Flexbox se diseñó para distribuir elementos en un eje principal. Grid facilita layouts 2D controlando filas y columnas con mayor precisión.'),(501,28,'¿Qué describe mejor el operador spread (...) cuando se usa en objetos?','Clona superficialmente y combina propiedades; las últimas propiedades sobrescriben a las anteriores','Hace deep clone automáticamente','Convierte el objeto en JSON','Solo funciona con arrays','A','{...a, ...b} crea un nuevo objeto con copia superficial (shallow). Si b tiene una propiedad igual, sobrescribe la de a.'),(502,28,'¿Qué método de array devuelve un nuevo array con la misma longitud transformando cada elemento?','filter','map','reduce','find','B','map transforma cada elemento y retorna un nuevo array. filter puede cambiar la longitud; find retorna un elemento; reduce retorna un acumulado.'),(503,28,'¿Qué describe mejor localStorage vs sessionStorage?','localStorage persiste entre sesiones; sessionStorage se mantiene solo en la pestaña/ventana actual','sessionStorage persiste siempre, localStorage se borra al cerrar pestaña','Ambos se borran automáticamente al recargar','localStorage solo guarda números y sessionStorage solo strings','A','localStorage persiste hasta que se borra manualmente; sessionStorage dura mientras la pestaña esté abierta. Ambos almacenan strings (se serializa con JSON).'),(504,28,'¿Qué es la ‘prop drilling’ en React?','Pasar props a través de varios niveles de componentes intermedios solo para llegar a un hijo lejano','Copiar un prop en localStorage para compartirlo','Usar hooks dentro de un bucle','Cambiar props del padre desde el hijo','A','Prop drilling es pasar datos/callbacks por varios componentes que no los necesitan, solo para entregar a un componente profundo. Puede mitigarse con Context o reestructuración.'),(505,28,'En React, ¿qué hace el optional chaining (?.) en JavaScript cuando se usa con llamadas?','Llama la función siempre aunque sea null','Llama la función solo si no es null/undefined; si lo es, devuelve undefined sin error','Convierte la función en async','Reemplaza useCallback','B','func?.() ejecuta la función solo si existe. Evita errores al llamar callbacks opcionales. También aplica a propiedades: obj?.prop.'),(506,28,'En JavaScript, ¿qué describe mejor el operador rest (...) en parámetros de función?','Agrupa argumentos restantes en un array','Expande un array en argumentos separados','Convierte argumentos en un objeto Map','Impide que una función reciba argumentos','A','function f(a, ...rest) {} captura los argumentos restantes en un array. Spread expande: f(...arr).'),(507,28,'¿Qué describe mejor la reconciliación (reconciliation) en React?','El proceso por el cual React compara el árbol anterior y el nuevo para aplicar cambios mínimos al DOM','El proceso por el cual React descarga dependencias npm','El proceso por el cual React convierte CSS a JS','El proceso de validar formularios automáticamente','A','Reconciliation es el diff del Virtual DOM/árbol de elementos para actualizar el DOM real de manera eficiente.'),(508,28,'¿Cuál afirmación sobre fetch es más correcta?','fetch rechaza la promesa automáticamente en cualquier status 4xx/5xx','fetch resuelve la promesa en errores HTTP; debes revisar response.ok/status para manejar 4xx/5xx','fetch solo funciona con GET','fetch siempre convierte la respuesta a JSON sin llamar .json()','B','fetch solo rechaza por errores de red. Para errores HTTP, response se resuelve y hay que verificar response.ok/status y luego parsear con response.json() si aplica.'),(509,28,'En React, ¿qué describe mejor la diferencia entre props y estado derivado (derived state)?','Props siempre se calculan con useMemo','Estado derivado es información calculada a partir de props/state existente; no siempre debe duplicarse en state','Estado derivado es obligatorio en formularios','Props y estado derivado son lo mismo','B','Derived state es un valor que puede calcularse (por ejemplo, filtrados, totales). Guardarlo en state puede causar desincronización; a veces basta con calcularlo en render o useMemo.'),(510,28,'¿Cuál afirmación sobre hoisting es la más correcta?','let y const se hoistean igual que var, sin excepciones','Las declaraciones con var se elevan (hoist) y se inicializan como undefined; let/const se hoistean pero quedan en TDZ','Las funciones no se hoistean','El hoisting solo existe en TypeScript','B','var se eleva e inicializa como undefined. let/const también se registran pero no son accesibles antes de su declaración por la Temporal Dead Zone (TDZ).'),(511,28,'En JavaScript, ¿qué diferencia más precisa hay entre == y ===?','== compara tipo y valor; === solo valor','=== compara tipo y valor; == hace coerción de tipos','Ambos comparan por referencia siempre','=== solo sirve para strings','B','=== es comparación estricta (sin coerción). == intenta convertir tipos (coerción), lo que puede producir resultados inesperados.'),(512,28,'¿Qué describe mejor la desestructuración en JavaScript?','Permite extraer propiedades/elementos en variables con una sintaxis compacta','Evita que se pueda reasignar una variable','Reemplaza completamente el uso de objetos','Solo aplica a funciones async','A','La desestructuración extrae valores: const {name} = obj; const [a,b] = arr. Se usa mucho en props y retornos de hooks.'),(513,28,'¿Qué describe mejor el ciclo de renderizado y efectos en React (hooks)?','useEffect se ejecuta antes del render para bloquear el pintado','Primero se ejecutan efectos, luego se pinta el DOM','Render genera JSX, React pinta cambios, luego se ejecutan efectos (useEffect)','useEffect se ejecuta solo una vez y nunca se vuelve a ejecutar','C','En general: React renderiza (calcula UI), luego aplica cambios al DOM y después corre efectos (useEffect) cuando cambian dependencias o en montaje.'),(514,28,'En React, ¿por qué se usa normalmente el patrón ‘callback props’ (pasar funciones como props)?','Para que el hijo pueda solicitar cambios al estado que vive en el padre','Para que el hijo modifique directamente los props','Para evitar usar eventos en el DOM','Para crear automáticamente CSS Modules','A','El estado suele vivir donde se necesita. El hijo recibe funciones para ‘pedir’ acciones (editar, borrar, navegar) sin romper el flujo unidireccional de datos.'),(515,28,'En Vite (React), ¿cómo se accede típicamente a variables de entorno definidas para el cliente?','process.env.MI_VAR','import.meta.env.MI_VAR (con prefijo VITE_ para exponer al cliente)','window.env.MI_VAR','globalThis.process.env.MI_VAR','B','Vite expone variables al cliente mediante import.meta.env y usualmente requiere el prefijo VITE_ para incluirlas en el bundle.'),(516,28,'En JSX, ¿qué diferencia hay entre class y className?','No hay diferencia; ambos funcionan igual','className es el atributo que se usa en JSX para asignar clases CSS','className solo funciona con CSS Modules','class es obligatorio cuando se usa Vite','B','En JSX se usa className porque class es palabra reservada en JavaScript. React mapea className al atributo class del DOM.'),(517,28,'¿Qué describe mejor la especificidad en CSS?','Una regla que define qué selector tiene prioridad cuando múltiples reglas aplican al mismo elemento','El orden del HTML siempre gana sin importar selectores','Solo importa en CSS Modules','Se basa únicamente en el tamaño del archivo CSS','A','La especificidad prioriza selectores (inline, IDs, clases/atributos, elementos). Si empatan, gana la regla que aparece más tarde (cascade).'),(518,28,'¿Cuál propiedad de CSS controla si width/height incluyen padding y border?','display','box-sizing','position','overflow','B','Con box-sizing: border-box, el width incluye padding y border. Con content-box (default), width es solo el contenido.'),(519,28,'¿Cuál es la diferencia más correcta entre renderizar null y renderizar un elemento vacío (<div />)?','null no renderiza nada; un elemento vacío agrega un nodo al DOM','null agrega un nodo invisible al DOM','Son idénticos en el DOM','null solo funciona con class components','A','Devolver null hace que React no inserte nodo. Un <div /> sí crea un elemento en el DOM, lo que puede afectar layout/estilos.'),(520,28,'En React, ¿qué hace el array de dependencias de useEffect?','Indica qué props se pueden mutar dentro del efecto','Determina qué valores, al cambiar, vuelven a ejecutar el efecto','Define el orden de renderizado de los componentes hijos','Convierte el efecto en una función memoizada','B','React vuelve a ejecutar el efecto cuando cambia alguna dependencia. [] significa “solo en montaje y desmontaje (cleanup)”. Sin array, corre después de cada render.'),(521,28,'¿Qué hace exactamente JSON.parse cuando el string no es JSON válido?','Devuelve null','Devuelve un objeto vacío','Lanza una excepción (SyntaxError)','Corrige el JSON automáticamente','C','JSON.parse lanza un error si el string no cumple el formato JSON. Por eso se suele envolver en try/catch al leer de localStorage.'),(522,28,'¿Qué paso es necesario para guardar un objeto en localStorage de forma correcta?','Guardarlo directamente: localStorage.setItem(\'k\', obj)','Serializar a string (JSON.stringify) antes de guardar','Convertirlo a ArrayBuffer','Usar setState en lugar de localStorage','B','localStorage almacena strings. Para objetos/arrays se usa JSON.stringify al guardar y JSON.parse al leer (con manejo de errores).'),(523,28,'¿Cuál es el riesgo más común de usar el índice del array como key en una lista React?','React no renderiza la lista si key no es un string','React forzará siempre un re-render completo del árbol','Puede mezclar estado/DOM entre elementos al reordenar o insertar/eliminar','La lista queda ordenada alfabéticamente por índice','C','Si key cambia por la posición, React puede “reutilizar” nodos equivocados cuando el array cambia, causando inputs con valores cruzados o estado asociado al ítem incorrecto.'),(524,28,'¿Cuál afirmación sobre CORS es la más correcta?','CORS es una política del navegador que controla solicitudes cross-origin; se habilita/define desde el servidor','CORS es un mecanismo del servidor que bloquea JavaScript local','CORS cifra el tráfico HTTP automáticamente','CORS evita XSS por completo','A','CORS es aplicado por el navegador. El servidor responde con headers (Access-Control-Allow-*) que permiten/deniegan orígenes y métodos.'),(525,28,'¿Qué describe mejor el operador nullish coalescing (??)?','Elige el operando derecho solo si el izquierdo es null o undefined','Elige el operando derecho si el izquierdo es falsy (incluye 0 y \'\')','Convierte un valor a boolean','Reemplaza a try/catch','A','?? usa el valor derecho únicamente cuando el izquierdo es null o undefined. Es distinto de ||, que trata 0, \'\' y false como falsy.'),(526,28,'¿Qué comportamiento es correcto sobre setState (useState) en React?','Actualiza el estado inmediatamente y siempre en forma síncrona','Puede agrupar (batch) actualizaciones; conviene usar la forma funcional cuando depende del valor previo','Reemplaza automáticamente objetos haciendo deep merge','No puede usarse dentro de eventos onClick','B','Las actualizaciones pueden batchearse. Si el nuevo valor depende del anterior, usar setX(prev => ...) evita estados obsoletos.'),(527,28,'¿Qué es un ‘handler’ de evento en React/JS?','Una variable global que contiene el DOM','Una función que se ejecuta en respuesta a un evento (click, change, submit, etc.)','Un tipo de hook que reemplaza useEffect','Un archivo de configuración de Vite','B','Un event handler es una función asociada a un evento. En React se pasa como prop: onClick={handleClick}, onChange={handleChange}, etc.'),(528,28,'¿Cuál es la finalidad principal de ESLint en un proyecto frontend?','Formatear el código (espacios, comillas) automáticamente en todos los casos','Detectar patrones problemáticos y errores potenciales en el código (linting)','Compilar JSX a JavaScript','Optimizar imágenes del proyecto','B','ESLint aplica reglas para encontrar errores, malas prácticas o inconsistencias. El formateo suele hacerlo Prettier (aunque pueden integrarse).'),(529,28,'En CSS Flexbox, ¿qué describe mejor justify-content?','Alinea elementos en el eje transversal (cross axis)','Distribuye elementos a lo largo del eje principal (main axis)','Cambia el orden de tabulación','Activa el modo grid','B','justify-content controla distribución en el eje principal (depende de flex-direction). align-items controla alineación en el eje transversal.'),(530,28,'En React, ¿qué significa que los eventos sean ‘sintéticos’?','Que React inventa eventos que no existen en el navegador','Que React envuelve eventos nativos en un sistema consistente entre navegadores','Que los eventos solo funcionan en modo producción','Que los eventos se ejecutan antes del render','B','React usa SyntheticEvent (históricamente) para normalizar comportamiento. Hoy se apoya más en eventos nativos, pero la idea sigue: una capa consistente.'),(531,28,'¿Qué describe mejor el renderizado condicional en React?','Mostrar u ocultar UI según una condición usando operadores como && o ternario','Usar siempre CSS display: none','Crear un archivo por cada condición','Solo se puede con switch-case','A','El render condicional decide qué JSX devolver según una condición: cond && <X/> o cond ? <A/> : <B/>.'),(532,28,'¿Cuál patrón es más apropiado para filtrar una lista por texto de búsqueda (case-insensitive)?','Convertir ambos (texto y query) a minúsculas y usar includes','Usar == para comparar strings','Usar Math.round en el string','Usar JSON.stringify para comparar','A','Un patrón común: const q = query.trim().toLowerCase(); item.name.toLowerCase().includes(q). También conviene manejar null/undefined.'),(533,28,'En un componente con inputs controlados (controlled components), ¿qué condición lo define?','El input no tiene onChange para evitar re-renders','El value del input proviene del state y se actualiza con onChange','El input siempre usa defaultValue y nunca value','El input solo puede existir dentro de un form con onSubmit','B','Un input controlado obtiene su valor desde el state (value={...}) y lo actualiza con onChange. Esto hace a React la “fuente de verdad”.'),(534,28,'¿Cuál práctica ayuda a evitar renders innecesarios en componentes hijos?','Mutar props para que no cambien','Mantener referencias estables (useCallback/useMemo) cuando sea necesario y usar memoización de componentes con criterio','Usar useEffect en lugar de useState','Llamar setState en cada render para sincronizar','B','Referencias de funciones/objetos cambian por render si se recrean. useCallback/useMemo pueden ayudar, junto con React.memo, siempre midiendo y evitando sobre-optimización.'),(535,28,'En HTML semántico, ¿qué beneficio principal aporta usar etiquetas como header, nav, main, footer?','Mejora accesibilidad y SEO al describir la estructura del documento','Hace que CSS Modules funcione','Reduce automáticamente el tamaño de imágenes','Evita el uso de JavaScript','A','Etiquetas semánticas ayudan a lectores de pantalla, herramientas y motores de búsqueda a entender la estructura.'),(536,28,'En JavaScript, ¿qué hace Array.prototype.find?','Devuelve un array con todos los elementos que cumplen la condición','Devuelve el primer elemento que cumple la condición o undefined','Devuelve el índice del primer elemento que cumple la condición','Devuelve true si todos cumplen la condición','B','find retorna el primer elemento que pasa el predicado. filter retorna todos. findIndex retorna el índice.'),(537,28,'En React, ¿cuándo es apropiado usar un cleanup en useEffect?','Cuando el efecto crea suscripciones/listeners/timers que deben limpiarse al desmontar o al cambiar dependencias','Cuando se quiere renderizar más rápido','Cuando se quiere cambiar props del padre','Solo cuando el array de dependencias está vacío','A','El cleanup (return () => ...) evita fugas: remover event listeners, cancelar timers o suscripciones. Corre en desmontaje y antes de re-ejecutar el efecto.'),(538,28,'¿Cuál diferencia describe mejor un componente ‘presentacional’ vs ‘contenedor’?','Presentacional: enfocado en UI; Contenedor: maneja estado/datos/acciones','Presentacional: siempre tiene useEffect; Contenedor: nunca','Presentacional: solo en class components','Contenedor: solo existe con Redux','A','Es una separación de responsabilidades: componentes de UI reciben props; contenedores orquestan estado, lógica y comunicación.'),(539,28,'En JavaScript, ¿qué diferencia precisa hay entre null y undefined?','null significa ‘ausencia intencional de valor’; undefined suele ser ‘no asignado/no definido’','undefined significa ‘vacío intencional’; null es ‘no definido’','Son exactamente iguales y se deben usar indistintamente','null solo existe en JSON','A','undefined suele aparecer cuando algo no está definido/asignado. null se usa intencionalmente para indicar ‘sin valor’. Ambos son distintos aunque null == undefined es true por coerción.'),(540,28,'En React, ¿cuál afirmación describe mejor la naturaleza de los props?','Son datos de entrada de solo lectura que el padre pasa al hijo','Son variables internas del componente que se actualizan con setState','Son valores globales compartidos sin necesidad de Provider','Son valores que React persiste automáticamente en localStorage','A','Los props son parámetros de un componente: entran desde el padre y no deberían mutarse en el hijo. Si se necesita cambiar algo, se suele pasar una función (callback) por props.'),(541,28,'¿Qué diferencia es más correcta entre PUT y PATCH en APIs REST?','PUT actualiza parcialmente; PATCH reemplaza completo','PUT suele reemplazar el recurso completo; PATCH aplica cambios parciales','PATCH solo existe en GraphQL','No existe diferencia','B','PUT suele enviar el recurso completo (idempotente). PATCH envía un conjunto de cambios parciales.'),(542,28,'¿Qué describe mejor el principio de ‘single source of truth’ en UI?','Cada componente mantiene su propia copia del mismo dato','Existe un lugar principal donde vive el estado, y los demás consumen esa fuente','Se debe guardar todo en localStorage','Se debe evitar usar props','B','Una única fuente de verdad evita inconsistencias. Por eso se centraliza state y se derivan vistas/props desde ahí.'),(543,28,'¿Qué hace el atributo type=\"button\" en un botón dentro de un form?','Hace que el botón envíe el formulario por defecto','Evita que el botón actúe como submit por defecto','Convierte el botón en un input','Impide que se pueda hacer click','B','Dentro de un form, un <button> sin type puede comportarse como submit. type=\"button\" evita envío accidental.'),(544,28,'¿Cuál es la razón más común para usar preventDefault() en un enlace (<a>) en una SPA?','Para evitar navegación completa y manejar la navegación con estado/router','Para que el enlace abra en una nueva pestaña','Para habilitar CSS Modules','Para convertirlo en un botón submit','A','En SPAs se evita la navegación tradicional del navegador para no recargar. Se usa preventDefault y se maneja navegación con router/estado.'),(545,28,'En HTTP, ¿qué código de estado representa ‘No encontrado’?','401','403','404','500','C','404 Not Found indica que el servidor no encontró el recurso. 401 es no autenticado, 403 es prohibido, 500 es error interno.'),(546,28,'¿Cuál es la forma correcta de actualizar estado inmutablemente cuando state es un array?','Modificar el array con push y luego llamar setState(state)','Reasignar state = nuevoArray sin usar setState','Crear un nuevo array (spread/map/filter) y pasarlo a setState','Cambiar el length del array y React detecta el cambio','C','En React se recomienda inmutabilidad: crear un nuevo array (por ejemplo [...prev, item], prev.filter(...), prev.map(...)) para que React detecte el cambio.'),(547,28,'En CSS, ¿qué describe correctamente el box model?','content + padding + border + margin','margin + background + font + content','content + border + outline + font','padding + outline + margin + grid','A','El box model define cómo se calcula el tamaño: contenido, padding, border y margin. box-sizing puede cambiar si width incluye padding/border.'),(548,28,'En HTTP, ¿qué método es más apropiado para obtener información sin modificar el recurso?','POST','PUT','GET','PATCH','C','GET se usa para recuperar recursos. POST crea/ejecuta acciones; PUT reemplaza; PATCH modifica parcialmente.'),(549,28,'¿Cuál método de array es el más adecuado para derivar un único valor (por ejemplo, suma total) desde un array?','reduce','map','filter','some','A','reduce combina elementos en un acumulador (número, objeto, string, etc.), ideal para totales, agrupaciones y conteos.'),(550,28,'¿Qué describe mejor el atributo aria-label?','Un atributo para cambiar estilos CSS','Un texto accesible para elementos sin etiqueta visible (ej. icon buttons)','Un atributo para cachear recursos','Un atributo exclusivo de imágenes','B','aria-label provee un nombre accesible. Útil cuando el contenido visual no describe el control (por ejemplo, un botón solo con icono).'),(551,28,'¿Qué diferencia es más correcta entre map y forEach en JavaScript?','map retorna un nuevo array; forEach retorna undefined','forEach retorna un nuevo array; map retorna undefined','Ambos retornan un nuevo array idéntico','map solo existe en React','A','map se usa para transformar y retornar un array nuevo. forEach ejecuta una función por elemento pero no retorna un array resultante.'),(552,28,'¿Cuál opción explica mejor por qué React recomienda no mutar objetos del state?','Porque mutar objetos hace que JavaScript lance un error','Porque React detecta cambios principalmente por referencia (shallow), y mutar puede impedir que detecte actualizaciones','Porque los objetos no pueden guardarse en state','Porque mutar obliga a usar TypeScript','B','Si se muta el mismo objeto, la referencia puede no cambiar y React podría no re-renderizar como esperas. Crear nuevos objetos/arrays facilita cambios predecibles.'),(553,28,'¿Qué diferencia describe mejor useEffect con [] vs sin array de dependencias?','Con [] corre una vez al montar; sin array corre después de cada render','Con [] corre después de cada render; sin array solo al montar','Con [] corre solo cuando cambia una prop; sin array nunca corre','No hay diferencia en absoluto','A','useEffect(fn, []) ejecuta en montaje (y cleanup en desmontaje). useEffect(fn) se ejecuta tras cada render.'),(554,28,'En React, ¿qué problema puede causar actualizar state durante el render (no en efecto/evento)?','Nada, es la forma recomendada','Puede causar un bucle infinito de renders','Evita que se ejecuten useEffect','Impide que funcionen las props','B','Si en el cuerpo del componente llamas setState, cada render dispara otro render, creando un loop. Se debe actualizar en handlers o effects con condiciones.'),(555,28,'¿Cuál opción describe mejor el propósito de React.Fragment (<>...</>)?','Agregar un div extra al DOM para agrupar','Agrupar múltiples elementos sin agregar un nodo extra al DOM','Crear un portal para modales','Crear un contexto global','B','Fragment permite devolver múltiples elementos desde un componente sin introducir un contenedor extra (div) en el DOM.'),(556,28,'¿Cuál opción explica mejor por qué se usa preventDefault() en onSubmit?','Para evitar que el navegador recargue la página al enviar el form','Para evitar que React haga re-render','Para convertir el submit en un GET','Para permitir usar localStorage','A','Por defecto, un submit puede navegar/recargar. preventDefault cancela la acción nativa y permite manejar el envío con JavaScript/React.'),(557,28,'En CSS, ¿qué diferencia es más correcta entre :hover y :active?',':hover aplica al pasar el mouse; :active mientras el elemento está siendo presionado',':active aplica al pasar el mouse; :hover al presionar','Ambos aplican solo en móviles','Ambos son equivalentes','A',':hover se activa al apuntar con el cursor. :active se activa en el momento del click/presión (mientras se mantiene presionado).'),(558,28,'En una SPA, ¿qué significa normalmente ‘navegación sin recarga’?','Cambiar de página siempre recarga el navegador','Cambiar vista cambiando estado/URL y renderizando componentes sin descargar el documento completo','Deshabilitar JavaScript','No hacer peticiones de red nunca','B','En una SPA se cambia la UI renderizada sin recargar el HTML completo. Puede hacerse con router o con estado propio que selecciona vistas.'),(559,28,'¿Qué es XSS (Cross-Site Scripting) en términos generales?','Un ataque que intenta adivinar contraseñas por fuerza bruta','Una vulnerabilidad que permite inyectar y ejecutar scripts en el navegador de otros usuarios','Un ataque que solo ocurre en bases de datos','Una política de CORS mal configurada','B','XSS ocurre cuando una app permite que contenido no confiable se interprete como código (JS/HTML). Se mitiga escapando/sanitizando y usando CSP.'),(560,28,'En React, ¿qué es un ‘Portal’?','Un mecanismo para renderizar un subtree en un nodo DOM diferente al contenedor principal','Un hook para manejar rutas','Una API para guardar en localStorage','Un tipo de CSS Module','A','ReactDOM.createPortal permite renderizar en otro lugar del DOM (útil para modales/tooltips), manteniendo el árbol React y eventos.'),(561,28,'¿Qué diferencia principal hay entre export default y export nombrado (named export) en ES Modules?','export default permite un export principal por módulo; named export permite múltiples exports con nombre','export default solo funciona en Node.js, no en el navegador','named export no puede importarse con llaves','No se pueden mezclar en el mismo archivo','A','default export se importa sin llaves con el nombre que quieras. Los named exports se importan con llaves y deben coincidir con el nombre exportado.'),(562,28,'¿Cuál práctica ayuda a construir UI responsive de forma general?','Usar unidades relativas (%, rem) y media queries; combinar con flex/grid','Usar siempre px para todo','Evitar flex y grid','Desactivar el viewport meta tag','A','Responsividad suele requerir layout flexible (flex/grid), unidades relativas y media queries para adaptarse a distintos tamaños de pantalla.'),(563,28,'En JavaScript, ¿qué describe mejor ‘truthy/falsy’?','Valores que solo aplican a números','Valores que se evalúan como true o false en contextos booleanos (if, &&, ||)','Valores que se comparan con ===','Valores exclusivos de React','B','Falsy incluye: false, 0, -0, 0n, \'\', null, undefined, NaN. Todo lo demás es truthy.'),(564,28,'¿Cuál es la diferencia más importante entre state y una variable normal (let) dentro de un componente React?','El state solo puede almacenar números; una variable normal puede almacenar objetos','Cambiar una variable normal re-renderiza; cambiar state no re-renderiza','Cambiar state programa un re-render; una variable normal se reinicia en cada render','El state es global para toda la app; una variable normal es local','C','El state (useState) se conserva entre renders y al actualizarse dispara una nueva renderización. Las variables locales se recalculan en cada render y su cambio no notifica a React.'),(565,28,'¿Cuál afirmación describe mejor la diferencia entre ‘build-time’ y ‘runtime’ en frontend?','Build-time: cuando se transpila/empaca el código; Runtime: cuando el código ya corre en el navegador','Build-time: cuando el usuario hace click; Runtime: cuando se instala npm','Build-time: cuando se renderiza JSX; Runtime: cuando se escribe CSS','No existe diferencia','A','Build-time es el proceso de bundling/transpilación (Vite). Runtime es la ejecución en el navegador del usuario. Algunas variables/optimizaciones ocurren solo en build.'),(566,28,'¿Qué describe mejor la diferencia entre spread y rest (ambos usan ...)?','Spread expande; Rest agrupa','Rest expande; Spread agrupa','Ambos solo sirven para objetos','Ambos solo sirven para funciones async','A','Spread (expansión) se usa al construir arrays/objetos o al llamar funciones. Rest (agrupación) se usa en parámetros o desestructuración para capturar el resto.'),(567,28,'¿Qué es “lifting state up” (levantar estado) en React?','Mover el state a un componente más alto que comparten varios hijos','Copiar el mismo state en cada hijo para evitar props','Convertir state en una constante para evitar re-render','Guardar state en localStorage automáticamente','A','Cuando varios componentes necesitan el mismo dato, se coloca el state en el ancestro común y se pasan datos/acciones por props.'),(568,28,'¿Qué describe mejor el concepto de “closure” en JavaScript?','Una función que se ejecuta siempre en el scope global','La capacidad de una función de recordar variables de su scope léxico aunque ese scope ya terminó','Un objeto que cierra el acceso a sus propiedades','Una promesa que se resuelve automáticamente','B','Un closure ocurre cuando una función mantiene acceso a variables de su entorno léxico. Es común en callbacks, handlers y hooks.'),(569,28,'En formularios web, ¿cuál es la diferencia más correcta entre onSubmit del form y onClick del botón?','onClick reemplaza a onSubmit en todos los casos','onSubmit permite manejar envío del form (incluye Enter) y se suele prevenir con preventDefault; onClick solo reacciona al clic','onSubmit solo existe en React, no en HTML','onClick siempre previene el refresh automáticamente','B','onSubmit se dispara al enviar el formulario (botón submit o Enter). Se usa preventDefault para evitar recarga. onClick solo captura clics.'),(570,28,'¿Qué problema resuelven principalmente los CSS Modules en proyectos React?','Hacer que CSS sea más rápido por compilarlo a JS','Evitar colisiones globales de nombres de clase mediante scope local','Permitir usar Tailwind sin instalarlo','Reemplazar por completo el DOM virtual','B','CSS Modules generan nombres de clase únicos por archivo, evitando colisiones y estilos globales accidentales. Se importan como objeto styles.'),(571,28,'¿Qué describe mejor useCallback?','Memoriza una función (su referencia) mientras no cambien dependencias','Memoriza el resultado de una función de cálculo','Ejecuta una función una vez por cada render','Transforma automáticamente callbacks en promesas','A','useCallback devuelve la misma referencia de función entre renders, útil cuando se pasa a hijos memoizados o dependencias de efectos.'),(572,28,'¿Cuál práctica mejora accesibilidad en imágenes informativas?','Omitir alt para que el lector de pantalla no las lea','Agregar un atributo alt descriptivo del contenido/propósito','Usar solo background-image en CSS siempre','Reemplazar img por div para mayor control','B','El atributo alt ofrece texto alternativo para lectores de pantalla y cuando la imagen no carga. Si la imagen es decorativa, alt=\'\' puede ser apropiado.'),(573,28,'En JavaScript, ¿qué describe mejor async/await?','Convierte código asíncrono en síncrono real, bloqueando el hilo','Es azúcar sintáctica sobre Promises para escribir flujo asíncrono más legible','Solo funciona dentro de useEffect','Reemplaza por completo el manejo de errores (try/catch)','B','async/await se basa en Promises; no bloquea el hilo. Permite escribir código asíncrono con estilo secuencial y manejar errores con try/catch.'),(574,28,'¿Qué describe mejor useMemo?','Memoriza una función para evitar que cambie de referencia','Ejecuta un efecto secundario después de pintar','Memoriza el resultado de un cálculo para evitar recalcular si dependencias no cambian','Reemplaza el uso de useState y useEffect','C','useMemo cachea el valor resultante de una función de cálculo. Se usa para optimizar cálculos costosos o estabilizar valores derivados.'),(575,28,'En el navegador, ¿qué ocurre primero en el event loop: microtasks o macrotasks?','Macrotasks siempre se ejecutan antes que microtasks','Microtasks (por ejemplo, .then) se vacían antes de pasar a la siguiente macrotask','No existe distinción entre microtasks y macrotasks','requestAnimationFrame es una microtask','B','Después de una macrotask, el engine ejecuta la cola de microtasks (Promises) antes de tomar la siguiente macrotask (setTimeout, eventos, etc.).'),(576,28,'¿Qué describe mejor el concepto de ‘debounce’ en UI?','Ejecutar una función inmediatamente por cada evento','Retrasar la ejecución hasta que deje de dispararse el evento por cierto tiempo','Ejecutar una función en paralelo en varios hilos','Cancelar todos los eventos del DOM','B','Debounce agrupa eventos frecuentes (tecleo, resize): ejecuta la acción cuando el usuario deja de disparar eventos durante un intervalo.'),(577,28,'¿Qué diferencia es más correcta entre componentes controlados y no controlados en formularios?','Controlado: el valor vive en state; No controlado: el DOM mantiene el valor (refs/defaultValue)','No controlado: requiere useEffect siempre; Controlado: nunca usa onChange','Controlado: solo para inputs type=number','No controlado: no se puede validar','A','En controlados, React controla el value; en no controlados, el input mantiene su estado y se accede vía refs o lectura del DOM.'),(578,28,'En React, ¿qué implica que el flujo de datos sea ‘unidireccional’?','Los hijos cambian directamente el estado de los padres','Los datos fluyen de padre a hijo por props; los cambios se piden con callbacks hacia arriba','Los datos fluyen solo de derecha a izquierda','Los datos se comparten automáticamente sin props','B','React favorece flujo de datos hacia abajo. Para cambios, se pasa una función al hijo y el padre actualiza su estado.'),(579,28,'En React, ¿para qué sirve principalmente la prop key al renderizar listas?','Para habilitar el acceso a props del padre desde el hijo','Para ayudar a React a identificar elementos entre renders y optimizar el diff','Para ordenar automáticamente la lista según el id','Para evitar que se ejecuten handlers de eventos dentro de la lista','B','key permite a React reconciliar listas: saber qué elemento es cuál entre renders, minimizando cambios y evitando bugs al insertar/eliminar/reordenar.'),(580,28,'En npm, ¿cuál diferencia describe mejor dependencies vs devDependencies?','dependencies se usan solo en desarrollo; devDependencies solo en producción','dependencies son necesarias para ejecutar la app; devDependencies para tooling/build/test','devDependencies se instalan siempre y dependencies nunca','No existe diferencia; solo cambia el orden en package.json','B','dependencies suelen ser requeridas en runtime (ej. react). devDependencies son herramientas (eslint, vite, prettier) que no se requieren para ejecutar la app ya compilada.'),(581,28,'En React, ¿por qué no se recomienda usar dangerouslySetInnerHTML con contenido no confiable?','Porque rompe el build de Vite','Porque puede introducir XSS al inyectar HTML sin sanitizar','Porque impide usar CSS Modules','Porque convierte el componente en class component','B','dangerouslySetInnerHTML inserta HTML literal en el DOM. Si el contenido proviene del usuario o de fuentes no confiables, puede ejecutar scripts maliciosos (XSS).'),(582,28,'En React, ¿cuál regla de Hooks es correcta?','Los hooks pueden llamarse dentro de if para optimizar','Los hooks deben llamarse siempre en el mismo orden, al nivel superior del componente','Los hooks solo pueden llamarse en class components','useState puede llamarse dentro de loops si es un array','B','Las reglas de hooks: llamarlos al nivel superior (no en loops/condicionales) para preservar el orden de llamadas entre renders.'),(583,28,'¿Qué describe mejor ‘throttle’ en UI?','Ejecutar una función como máximo una vez cada cierto intervalo','Ejecutar una función solo al final de una ráfaga','Ejecutar una función solo si hay un error','Ejecutar una función de forma síncrona bloqueante','A','Throttle limita frecuencia: por ejemplo, máximo 1 vez cada 100ms. Debounce espera a que termine la ráfaga.'),(584,28,'En Vite, ¿qué comando suele generar la build de producción?','npm run build','npm run dev','npm run lint','npm run preview --watch','A','En proyectos Vite, normalmente el script build genera assets optimizados para producción. dev inicia el servidor de desarrollo. preview sirve para previsualizar la build.'),(585,30,'¿Cuál es el primer paso recomendado antes de escribir el código de un algoritmo complejo?','Compilar el programa.','Definir las variables globales en la base de datos.','Realizar un análisis del problema y diseñar un diagrama de flujo o pseudocódigo.','Comprar una licencia de un lenguaje de programación.','C','La planeación mediante pseudocódigo evita errores de lógica estructural que son difíciles de corregir una vez codificados.'),(586,30,'¿Cuál es el propósito del operador módulo (%) en programación?','Calcular el porcentaje de un número.','Dividir dos números y devolver el cociente entero.','Obtener el residuo o resto de una división entera.','Elevar un número a una potencia.','C','El módulo es fundamental para lógica de ciclos y condicionales, como determinar si un número es par (n % 2 == 0).'),(587,30,'En lógica de programación, ¿qué representa el proceso de \'Inicialización\'?','Es el acto de borrar el contenido de la memoria caché.','Asignar un tipo de dato a una variable sin darle un valor.','Asignar un valor inicial a una variable antes de ser utilizada por primera vez.','El momento en que el código se traduce a lenguaje máquina.','C','Utilizar una variable sin inicializar suele provocar errores de \'basura en memoria\' o valores nulos (null/undefined), por lo que darle un valor inicial es una buena práctica esencial.'),(588,30,'Si necesitas guardar el resultado de 7 / 2 como 3.5 (con decimales), ¿qué tipo de dato es más adecuado para la variable resultado?','Entero (Integer)','Flotante/Decimal (Float/Double)','Booleano (Boolean)','Carácter (Char)','B','Un tipo flotante permite representar valores con parte decimal. Con enteros, muchas veces la división se trunca y se pierde la parte decimal.'),(589,30,'De acuerdo a las buenas prácticas (CamelCase), ¿cuál sería el nombre correcto para una variable que guarda el precio final de un producto?','PRECIO_FINAL','precio_final','precioFinal','PrecioFinal','C','CamelCase inicia con minúscula y cada palabra siguiente con mayúscula. La opción D (PascalCase) suele usarse para clases, y la A (SNAKE_CASE_MAYUS) para constantes.'),(590,30,'¿Cuál es el resultado de la concatenación de \'Hola\' + \'Mundo\'?','HolaMundo','Hola Mundo','Error: no se pueden sumar palabras.','2','A','La concatenación une las cadenas tal cual están. Si no hay un espacio dentro de las comillas, los textos se pegan directamente.'),(591,30,'Si i inicia en 0 y se ejecuta un ciclo mientras i < 10, pero dentro del ciclo nunca se cambia i, ¿qué es lo más probable que ocurra?','El ciclo se ejecuta exactamente 10 veces.','El ciclo se ejecuta 9 veces y se detiene.','El ciclo puede volverse infinito porque la condición nunca cambia.','El programa compila pero siempre salta el ciclo.','C','Si i nunca se actualiza, seguirá siendo 0 y la condición i < 10 permanecerá verdadera, causando un bucle infinito.'),(592,30,'¿Cuál es el resultado de la expresión: True OR False AND False (asumiendo que AND se evalúa antes que OR)?','True','False','Error de sintaxis','No se puede evaluar sin un ciclo','A','Primero se evalúa False AND False = False. Luego True OR False = True. La prioridad de operadores influye en el resultado.'),(593,30,'¿Qué resultado arroja la expresión lógica: (5 > 3) AND (10 < 8)?','True','False','Error de sintaxis','15','B','En una operación AND, ambas condiciones deben ser verdaderas. Aunque (5 > 3) es verdadero, (10 < 8) es falso, invalidando toda la expresión.'),(594,30,'¿Qué significa que un algoritmo sea \'Finito\'?','Que debe ser muy delgado al escribirse.','Que debe tener un número determinado de pasos y terminar en algún momento.','Que solo puede procesar números pequeños.','Que no puede ser traducido a otros idiomas.','B','Un proceso que no termina nunca no es un algoritmo funcional, es un error o un proceso infinito.'),(595,30,'En muchos lenguajes, ¿qué diferencia práctica hay entre usar \'=\' y \'==\' dentro de una condición?','\'=\' compara dos valores y \'==\' asigna un valor a una variable.','\'=\' se usa para asignar un valor, mientras que \'==\' se usa para comparar si dos valores son iguales.','Ambos operadores hacen exactamente lo mismo dentro de una condición.','\'==\' solo funciona con números y \'=\' solo con texto.','B','En la mayoría de lenguajes, \'=\' realiza asignación y \'==\' realiza comparación. Confundirlos suele causar errores de lógica o de compilación según el lenguaje.'),(596,30,'En una división, ¿cuál afirmación describe mejor por qué a veces 5 / 2 da 2 y otras veces da 2.5?','Siempre da 2.5, porque toda división produce decimales.','Depende de si se usan números enteros o decimales: con enteros puede truncar y con decimales conserva la parte decimal.','Siempre da 2, porque el residuo se elimina en cualquier lenguaje.','Da error, porque no se puede dividir 5 entre 2.','B','La forma en que se calcula la división puede depender del tipo de dato. Con enteros, algunos lenguajes realizan división entera (truncada).'),(597,30,'¿Para qué sirve la estructura \'Switch\' o \'Según sea\'?','Para repetir un bloque de código muchas veces.','Para manejar múltiples condiciones basadas en el valor de una sola expresión.','Para declarar variables globales.','Para conectar la base de datos.','B','Es una alternativa más limpia a múltiples \'If-Else\' anidados cuando se evalúa una misma variable contra varios valores posibles.'),(598,30,'En la jerarquía de operadores matemáticos, ¿cuál se ejecuta primero?','Suma y Resta.','Multiplicación y División.','Paréntesis.','Asignación (=).','C','Los paréntesis tienen la prioridad más alta para agrupar operaciones, seguidos de potencias, raíces, mult/div y sum/rest.'),(599,30,'Si una variable se declara dentro de un ciclo \'For\', ¿se puede acceder a ella fuera del ciclo en lenguajes con \'Block Scope\'?','Sí, siempre.','No, la variable solo existe dentro del bloque del ciclo.','Solo si es una constante.','Solo si el ciclo se ejecutó más de 10 veces.','B','El alcance (scope) define que las variables declaradas dentro de llaves {} o bloques suelen morir al salir de ellos.'),(600,30,'¿Qué tipo de dato devolvería la comparación (10 == \'10\') en un lenguaje con tipado estricto?','Verdadero (True)','Falso (False) o Error','1010','Nulo (Null)','B','En tipado estricto, un Entero y una Cadena de texto son tipos diferentes, por lo que la comparación falla aunque el contenido \'parezca\' igual.'),(601,30,'Si un ciclo debe ejecutarse mientras la variable \'energía\' sea mayor a 0, ¿cuál es la condición correcta?','energia == 0','energia < 0','energia > 0','energia != 0','C','La condición debe ser verdadera para que el ciclo continúe; por lo tanto, \'energia > 0\' es la que valida la permanencia.'),(602,30,'¿Cuál es la principal característica del ciclo \'While\'?','Se ejecuta un número exacto de veces definido al inicio.','Se ejecuta mientras una condición sea verdadera, evaluándola antes de cada iteración.','Solo se utiliza para recorrer arreglos.','Se ejecuta al menos una vez, sin importar la condición.','B','El \'While\' es un ciclo de pre-condición. Si la condición es falsa desde el principio, el bloque de código nunca se ejecuta.'),(603,30,'¿Qué es un comentario en el código?','Una instrucción que el usuario lee en pantalla.','Texto ignorado por el compilador usado para explicar la lógica a otros humanos.','Un mensaje de error del sistema.','Una variable que guarda opiniones.','B','Los comentarios son vitales para el mantenimiento del código, permitiendo que otros programadores entiendan qué se intentó hacer.'),(604,30,'¿Qué es la indentación (sangría) y por qué es importante?','Es un tipo de variable para textos largos.','Es el espacio al inicio de las líneas para indicar qué bloques de código pertenecen a otros.','Es una función para imprimir en pantalla.','Es un método para encriptar contraseñas.','B','La indentación mejora la legibilidad y, en lenguajes como Python, es obligatoria para definir la jerarquía del código.'),(605,30,'Si quieres intercambiar los valores de a y b sin perder ninguno, ¿cuál enfoque es el más seguro en un algoritmo básico?','Asignar a = b y luego b = a, sin usar nada más.','Asignar b = a y luego a = b, sin usar nada más.','Usar una variable temporal: temp = a; a = b; b = temp.','Sumar los valores: a = a + b; b = a + b; a = a - b.','C','La variable temporal conserva el valor original de a mientras se reasigna, evitando que uno de los valores se sobrescriba antes de tiempo.'),(606,30,'¿Cuántas veces se ejecuta el cuerpo de un ciclo si inicia en i = 1 y repite mientras i < 5, aumentando i en 1 cada vez?','3 veces','4 veces','5 veces','Es un bucle infinito','B','Con i < 5, las iteraciones ocurren para i = 1, 2, 3 y 4. Cuando i llega a 5, la condición deja de cumplirse.'),(607,30,'Si la regla es: si nota >= 3.0 entonces \'Aprueba\', en caso contrario \'Reprueba\', ¿qué sucede cuando nota = 3.0?','Aprueba','Reprueba','Da error porque 3.0 no es válido','Se salta la condición y no muestra nada','A','El operador >= incluye el límite. Si nota es exactamente 3.0, la condición se cumple y se ejecuta la rama de aprobación.'),(608,30,'En un ciclo, ¿qué efecto tiene la instrucción \'continue\' (en los lenguajes que la soportan)?','Finaliza el ciclo por completo y sale de él.','Salta al inicio de la siguiente iteración, omitiendo el resto de instrucciones de la iteración actual.','Repite la misma iteración sin volver a evaluar la condición.','Declara una variable para continuar el programa.','B','\'continue\' no termina el ciclo; solo omite lo que falta de la iteración actual y vuelve al control del ciclo para seguir con la siguiente.'),(609,30,'En un ciclo \'For\', ¿cuáles son los tres elementos que suelen definirse en la cabecera?','Variable, Condición y Tipo de dato.','Inicialización, Condición e Incremento/paso.','Nombre, Valor y Salida.','Entrada, Proceso y Salida.','B','El ciclo \'For\' agrupa la inicialización del contador, la condición de permanencia y cómo cambia el contador en una sola línea.'),(610,30,'¿Para qué sirve el tipo de dato \'Booleano\'?','Para almacenar números con muchos decimales.','Para representar valores de lógica binaria: Verdadero o Falso.','Para guardar fechas y horas.','Para listas de nombres.','B','Es el tipo de dato más simple y fundamental para la toma de decisiones en condicionales.'),(611,30,'¿Cuál es la principal diferencia entre una variable y una constante en la ejecución de un programa?','La variable ocupa espacio en memoria RAM y la constante no.','El valor de la variable puede cambiar, mientras que el de la constante permanece inalterado tras su asignación.','Las variables solo almacenan números y las constantes solo texto.','Las constantes se declaran dentro de los ciclos y las variables fuera de ellos.','B','Por definición, una constante protege un valor durante todo el ciclo de vida del programa, mientras que la variable está diseñada para ser reasignada según la lógica del algoritmo.'),(612,30,'¿Qué valor booleano resulta de: NOT(5 == 5)?','True','False','5','Null','B','5 == 5 es True. El operador NOT invierte el valor, convirtiéndolo en False.'),(613,30,'En el contexto de ciclos, ¿qué es un \'Bucle Infinito\'?','Un ciclo que procesa grandes cantidades de datos.','Un error de lógica donde la condición de salida nunca se vuelve falsa.','Un ciclo diseñado para durar exactamente 24 horas.','Una estructura que usa demasiada memoria RAM.','B','Si la variable de control nunca cambia o la condición siempre es verdadera, el programa queda atrapado, consumiendo recursos sin finalizar.'),(614,30,'¿Qué es un \'Contador\' en programación?','Una variable que se incrementa o decrementa en un valor constante (usualmente 1).','Una función que mide el tiempo de ejecución.','Una variable que guarda la suma de valores variables.','Un tipo de dato especial para finanzas.','A','Los contadores se usan para llevar el registro de iteraciones (ej: i = i + 1).'),(615,30,'¿Qué es un \'Acumulador\'?','Una variable que siempre aumenta de 1 en 1.','Una estructura que guarda nombres de variables.','Una variable que suma valores variables en cada iteración.','Un método para borrar la memoria.','C','A diferencia del contador, el acumulador suma montos distintos (ej: total = total + precioArticulo).'),(616,30,'¿Cuál es el valor de la variable \'x\' tras ejecutar: x = 10; x = x + 5; x = x * 2;?','20','25','30','15','C','Sigue un orden secuencial: 10 + 5 = 15; luego 15 * 2 = 30.'),(617,30,'Si necesitas almacenar la cantidad de hijos de una persona, ¿cuál es el tipo de dato más adecuado?','Flotante (Float/Double)','Booleano','Entero (Integer)','Cadena (String)','C','La cantidad de hijos es una unidad discreta y contable que no admite decimales, por lo que un entero es el tipo de dato óptimo.'),(618,30,'¿Qué diferencia al ciclo \'Do-While\' del ciclo \'While\'?','El Do-While es más rápido.','El Do-While evalúa la condición al final, garantizando al menos una ejecución del bloque.','El While solo funciona con números enteros.','No hay diferencia, son sinónimos en todos los lenguajes.','B','A diferencia del \'While\' estándar, el \'Do-While\' ejecuta el cuerpo del ciclo primero y luego pregunta si debe continuar.'),(619,30,'Si edad = 17 y permisoEspecial = True, ¿qué resultado tiene la condición (edad >= 18) OR (permisoEspecial == True)?','True','False','Error de sintaxis','Depende del lenguaje, nunca se puede saber','A','En un OR basta con que una condición sea verdadera. Aunque edad >= 18 es falso, permisoEspecial == True es verdadero, así que toda la condición resulta verdadera.'),(620,30,'¿Qué operador se utiliza para verificar si dos valores son DISTINTOS?','==','=','!=','<>','C','El operador de desigualdad es \'!=\' en la mayoría de lenguajes modernos (C, Java, Python, JS).'),(621,30,'¿Cuál es la función principal de un algoritmo?','Diseñar interfaces gráficas atractivas.','Escribir código que solo las computadoras entiendan.','Definir una serie de pasos ordenados y finitos para resolver un problema.','Aumentar la velocidad del procesador.','C','Un algoritmo es una receta lógica: debe ser finito, preciso y resolver una situación específica independientemente del lenguaje.'),(622,30,'¿Qué sucede en un flujo de control si la condición de un \'If\' es falsa y no existe un \'Else\'?','El programa se detiene con un error.','El programa salta el bloque de código del If y continúa con la siguiente instrucción fuera de él.','El programa vuelve a evaluar la condición indefinidamente.','Se ejecuta el código dentro del If por defecto.','B','El bloque \'Else\' es opcional. Si la condición no se cumple y no hay alternativa definida, el flujo simplemente sigue su curso normal.'),(623,30,'¿Qué es una \'Prueba de Escritorio\'?','Limpiar el lugar de trabajo del programador.','Seguir manualmente los pasos de un algoritmo con valores de ejemplo para verificar el resultado.','Un examen para comprar una computadora nueva.','Instalar el software en la PC del cliente.','B','Es la técnica manual para validar la lógica antes de programar, simulando cómo cambiarían las variables paso a paso.'),(624,30,'¿Cuál de estos es un error de lógica y no de sintaxis?','Olvidar un punto y coma.','Escribir \'whle\' en lugar de \'while\'.','Calcular el promedio dividiendo la suma por un número incorrecto de elementos.','No cerrar un paréntesis.','C','Los errores de sintaxis impiden que el programa corra. Los de lógica permiten que corra, pero dan resultados incorrectos.'),(625,30,'Dada la expresión lógica: NOT(True AND False) OR False, ¿cuál es el resultado?','True','False','Indeterminado','Depende del lenguaje','A','True AND False = False; NOT(False) = True; True OR False = True.'),(626,30,'En pseudocódigo, si i empieza en 1 y mientras i <= 5 haces i = i + 2, ¿cuántas veces se ejecuta el cuerpo del ciclo?','2 veces','3 veces','4 veces','5 veces','B','Los valores de i serán 1, 3 y 5. Se ejecuta 3 veces antes de que i pase a 7 y falle la condición.'),(627,30,'Se desea encontrar el primer número mayor que 0 en una lista. ¿Qué control de flujo es más adecuado?','Seguir recorriendo toda la lista aunque ya se encontró.','Usar un ciclo con una bandera (encontrado) y romper (break) al hallarlo.','Usar únicamente condicionales anidados sin ciclos.','Sumar todos los números y dividir por la longitud.','B','Una bandera o una interrupción temprana optimiza el recorrido al detenerse cuando se cumple el objetivo.'),(628,30,'Para validar una contraseña no vacía, ¿cuál condición es adecuada?','si longitud(contraseña) > 0','si contraseña == \'\' o longitud(contraseña) > 0','si longitud(contraseña) >= -1','si longitud(contraseña) < 0','A','Una contraseña no vacía implica longitud estrictamente mayor que 0.'),(629,30,'En un ciclo anidado (dos niveles), ¿qué efecto tiene \'romper\' (break) en el ciclo interno?','Detiene ambos ciclos siempre.','Solo detiene el ciclo interno; el externo continúa con su siguiente iteración.','No tiene efecto en ningún ciclo.','Reinicia el programa desde el inicio.','B','El \'break\' afecta el ciclo donde se ejecuta; el externo sigue según su propia condición.'),(630,30,'¿Qué sucede con la variable \'suma\' en: suma = 0; para i desde 1 hasta 4: si i == 3 entonces continuar; suma = suma + i?','suma = 10','suma = 7','suma = 6','suma = 3','B','Se omite i=3 por \'continuar\'; se suman 1, 2 y 4 → 7.'),(631,30,'Si un ciclo \'repetir hasta\' finaliza cuando suma >= 100, ¿qué característica tiene su condición de parada?','Se evalúa al inicio del ciclo.','Se evalúa al final, por lo que el cuerpo se ejecuta al menos una vez.','Depende del compilador.','No tiene condición de parada.','B','\'Repetir...hasta\' comprueba la condición al final, garantizando al menos una ejecución.'),(632,30,'Si n = 1234 y se hace: contar = 0; mientras n > 0: n = n / 10 (entera); contar = contar + 1. ¿Qué valor tendrá \'contar\'?','2','3','4','5','C','Se eliminan dígitos enteros sucesivamente: 1234→123→12→1→0. Se cuentan 4 iteraciones.'),(633,30,'¿Cuál opción representa correctamente la negación de (A > 0 AND B <= 10) usando las leyes de De Morgan?','A <= 0 AND B > 10','A <= 0 OR B > 10','A > 0 OR B <= 10','NOT(A > 0) AND NOT(B <= 10)','B','NOT(X AND Y) equivale a NOT X OR NOT Y: NOT(A>0) es A<=0; NOT(B<=10) es B>10.'),(634,30,'Se requiere contar cuántos números negativos hay en una lista. ¿Cuál patrón es más adecuado?','Un acumulador que sume los valores negativos.','Un contador que aumente en 1 cada vez que un elemento sea negativo.','Un ciclo sin cuerpo y solo una condición.','Un \'según sea\' con todos los números posibles.','B','Para contar elementos que cumplen una condición se utiliza un contador, no un acumulador.'),(635,30,'Si se ejecuta: suma = 0; para i desde 2 hasta 10 paso 2: suma = suma + i. ¿Cuál es el valor de suma?','20','24','30','32','C','Se suman 2+4+6+8+10 = 30.'),(636,30,'¿Cuál es la condición correcta para repetir la lectura de una nota hasta que esté en el rango [0, 5]?','mientras nota < 0 y nota > 5','mientras nota <= 0 o nota >= 5','mientras nota < 0 o nota > 5','mientras nota == 0 y nota == 5','C','Se repite mientras esté fuera del rango; es decir, si es menor que 0 o mayor que 5.'),(637,30,'En una cadena de \'si - sino si - sino\', ¿cuándo se ejecuta el bloque \'sino\'?','Siempre, después del primer \'si\'.','Solo si todas las condiciones anteriores fueron falsas.','Cuando la primera condición es verdadera.','Cuando alguna condición intermedia es verdadera.','B','\'sino\' actúa como caso por defecto: se ejecuta si ninguna condición previa fue verdadera.'),(638,30,'Al calcular el promedio de N valores ingresados por el usuario, ¿qué estructura es más apropiada si se conoce N de antemano?','Un ciclo \'para\' con N iteraciones.','Un \'mientras verdadero\' sin condición de salida.','Un \'según\' con N casos.','Solo condicionales, sin ciclos.','A','Cuando se conoce el número fijo de repeticiones, un \'para\' es directo y claro.'),(639,30,'¿Cuál es la forma correcta de verificar que un número N está entre 1 y 100 (incluidos)?','si N > 1 y N < 100','si N >= 1 y N <= 100','si N == 1 o N == 100','si N < 1 o N > 100','B','Incluir los límites requiere usar >= y <= en la condición compuesta.'),(640,30,'¿Qué problema describe mejor un error de \'off-by-one\' (desfase de uno) en ciclos?','El ciclo nunca inicia.','El ciclo itera una vez más o una vez menos de lo esperado por usar < en lugar de <= (o viceversa).','El ciclo no modifica su contador.','El ciclo se ejecuta infinitamente por una condición siempre verdadera.','B','El error de desfase de uno ocurre por límites incorrectos en la condición del ciclo.'),(641,30,'En pseudocódigo: contador = 0; para i desde 1 hasta 5 hacer: si i % 2 == 0 entonces contador = contador + 1. ¿Cuál es el valor final de contador?','1','2','3','4','B','Los pares entre 1 y 5 son 2 y 4; se cuentan 2 valores.'),(642,30,'Si total empieza en 0 y se lee precio hasta que sea -1 (sentinela), sumando cada precio válido, ¿qué condición del ciclo es correcta?','mientras precio == -1','mientras precio != -1','repetir hasta precio != -1','siempre','B','Se itera mientras el valor leído no sea el sentinela; cuando es -1, se detiene.'),(643,30,'¿Cuál es el objetivo de usar una variable bandera (flag) en un algoritmo?','Controlar el formato de impresión.','Recordar si cierto evento/condición ya ocurrió para tomar decisiones posteriores.','Incrementar un contador automáticamente.','Forzar la salida de todos los ciclos.','B','Las banderas almacenan estados lógicos (verdadero/falso) para guiar el flujo según eventos previos.'),(644,30,'¿Qué valor final tiene \'i\' después de: i = 0; mientras i < 3: i = i + 1?','0','1','2','3','D','El ciclo ejecuta i=1, i=2, i=3; al llegar a 3 termina, quedando i en 3.'),(645,30,'En un \'según sea\' (switch) con casos 1, 2, 3 y un caso por defecto, si la variable vale 4, ¿qué bloque se ejecuta?','El caso 1','El caso 2','El caso 3','El caso por defecto','D','Al no coincidir 4 con ningún caso explícito, se ejecuta el bloque por defecto.'),(646,31,'Sobre variables locales en Java, es correcto afirmar que…','Tienen un valor por defecto asignado por la JVM.','Deben inicializarse antes de su primer uso.','Se inicializan a null automáticamente.','Se comparten entre métodos del mismo paquete.','B','Las variables locales no reciben valor por defecto; deben asignarse antes de ser utilizadas.'),(647,31,'¿Qué efecto tiene la instrucción continue dentro de un bucle?','Termina el bucle por completo.','Salta a la siguiente iteración del mismo bucle.','Reinicia el método que contiene el bucle.','Crea un nuevo hilo de ejecución.','B','continue finaliza la iteración actual y pasa a la siguiente.'),(648,31,'En StringBuilder, ¿qué hace append?','Reemplaza el contenido actual.','Inserta al principio del contenido.','Agrega al final del contenido actual.','Vacía el contenido y agrega el nuevo.','C','append añade al final, aprovechando la mutabilidad de StringBuilder.'),(649,31,'¿Qué ocurre si intentas usar el resultado de un método void dentro de una expresión (p. ej., int x = metodoVoid();)?','Se evalúa como 0.','Se evalúa como null.','No compila porque void no produce valor.','Se convierte implícitamente a boolean.','C','void indica ausencia de valor de retorno, por lo que no puede usarse donde se espera un valor.'),(650,31,'¿Qué implica declarar una variable local como final?','No puede leerse fuera del método.','No puede reasignarse después de su primera asignación.','No puede usarse en expresiones lógicas.','Se convierte en estática.','B','final en variables impide la reasignación; el valor (si es objeto) puede cambiar su estado interno.'),(651,31,'¿Cuál es la diferencia principal entre while y do-while en Java?','Ambos evalúan la condición al final del bucle.','do-while ejecuta el bloque al menos una vez; while podría no ejecutarlo nunca.','while solo funciona con boolean y do-while con int.','do-while no permite la instrucción break.','B','do-while evalúa la condición al final, garantizando una ejecución mínima; while la evalúa al inicio.'),(652,31,'Con Scanner sc, ¿qué método lee una línea completa de texto (incluyendo espacios)?','sc.next()','sc.nextChar()','sc.nextLine()','sc.readLine()','C','nextLine() captura la línea completa hasta el salto de línea; next() solo el siguiente token.'),(653,31,'¿Es posible usar tipos enum en una sentencia switch tradicional?','Sí, y puedes usar los identificadores del enum como casos.','No, solo int y char.','Sí, pero únicamente con cast explícito a int.','Solo dentro de clases abstractas.','A','switch admite enum y permite comparar directamente contra sus constantes.'),(654,31,'¿A qué if se asocia un else cuando hay if anidados sin llaves?','Al if más externo.','Al if más reciente (más cercano) que no tenga else.','A todos los if simultáneamente.','Al if con condición verdadera.','B','Por regla de asociación, un else se une al if más cercano que carece de else.'),(655,31,'¿Para qué sirve un import static de java.lang.Math.*?','Para poder invocar métodos de Math sin prefijo, como sqrt(4).','Para convertir todos los métodos en estáticos.','Para generar automáticamente javadocs.','Para cargar la clase más rápido.','A','El import static permite usar miembros estáticos sin calificar con el nombre de la clase.'),(656,31,'¿Cuál es una implementación correcta de un setter para un campo privado String nombre?','public void setNombre(String n) { nombre = n; }','public String setNombre(String nombre) { return nombre; }','void setNombre() { this.nombre = nombre; }','public setNombre(String nombre) { this.nombre = nombre; }','A','Un setter típico retorna void y asigna el parámetro al campo; no necesita devolver valor.'),(657,31,'¿Cuál es la forma correcta de inicializar un arreglo con valores literales?','int[] a = new int(1,2,3);','int a[] = {1, 2, 3};','int a = {1, 2, 3};','int[] a = new {1, 2, 3};','B','La sintaxis literal válida es tipo nombre[] = {v1, v2, ...}; o int[] a = { ... }.'),(658,31,'Dado int x = 5; int y = x++; ¿cuáles son los valores resultantes?','x = 5, y = 6','x = 6, y = 5','x = 6, y = 6','x = 5, y = 5','B','El post-incremento asigna primero y = 5 y luego incrementa x a 6.'),(659,31,'Si defines un constructor público con parámetros y también uno vacío público, ¿qué ventaja ofrece el vacío?','Permite crear instancias sin datos iniciales y configurar luego vía setters.','Obliga a usar siempre valores por defecto.','Impide el uso del constructor con parámetros.','Hace la clase abstracta.','A','El constructor vacío facilita escenarios donde se requiere construcción sin datos, por ejemplo frameworks de mapeo/serialización.'),(660,31,'Respecto al paso de parámetros en Java, ¿qué es correcto para tipos primitivos?','Se pasan por referencia.','Se pasan por valor (se copia el valor).','Se pasan por aliasing dinámico.','Depende del compilador.','B','En Java todo se pasa por valor; en primitivos se copia el valor numérico/booleano.'),(661,31,'En un switch con enum, ¿cómo deben escribirse las etiquetas case?','Con el nombre del enum como prefijo obligatorio.','Con el ordinal del enum (enteros).','Con las constantes del enum, p. ej., case ROJO:','Como Strings con el nombre de la constante.','C','Se usan directamente las constantes del enum en los case, sin comillas ni ordinales.'),(662,31,'¿Qué sintaxis define un método con argumentos variables (varargs) de tipo int?','void sumar(int args[])','void sumar(int... numeros)','void sumar(...int numeros)','void sumar(var int numeros)','B','Los varargs usan la sintaxis tipo... nombre, por ejemplo int... numeros.'),(663,31,'¿Qué hace la instrucción return en un método void?','Devuelve null al llamador.','Finaliza el método inmediatamente sin valor de retorno.','Reinicia la ejecución del método.','Devuelve un valor por defecto.','B','return; en métodos void sirve para salir de forma anticipada sin devolver valor.'),(664,31,'En una clase con campos privados, ¿qué rol cumplen getters y setters?','Romper la encapsulación y exponer los campos.','Proveer acceso controlado y validable al estado interno.','Sustituir constructores en todos los casos.','Eliminar la necesidad de inicialización.','B','Permiten encapsular: exponer lectura/escritura controlada, validaciones y mantener invariantes.'),(665,31,'Sobre String.substring(inicio, fin), ¿qué es correcto?','El índice fin es inclusivo.','Los índices son 1-based.','El índice fin es exclusivo.','Modifica el String original.','C','substring usa inicio inclusivo y fin exclusivo; String es inmutable.'),(666,31,'En un método, ¿qué sucede con los parámetros si cambias sus valores dentro del método?','El cambio siempre afecta a las variables del llamador.','Nunca afecta al llamador, porque Java pasa por valor.','Afecta solo si el método es static.','Depende del número de parámetros.','B','Se trabaja sobre copias (valores o referencias copiadas); reasignar el parámetro no cambia la variable del llamador.'),(667,31,'¿En qué rango devuelve valores Math.random()?','[0.0, 1.0]','(0.0, 1.0]','[0.0, 1.0)','(0.0, 1.0)','C','Devuelve un double x tal que 0.0 ≤ x < 1.0.'),(668,31,'¿Cuál es la convención de nombres para constantes en Java?','camelCase (ej. maxTamano)','PascalCase (ej. MaxTamano)','mayúsculas con guiones bajos (ej. MAX_TAMANO)','snake_case (ej. max_tamano)','C','Las constantes (static final) se nombran en MAYÚSCULAS separadas por guion bajo.'),(669,31,'¿Qué hace el método trim() de String?','Elimina todos los espacios del texto.','Elimina espacios en blanco al inicio y al final de la cadena.','Convierte a minúsculas y quita espacios.','Recorta la cadena a una longitud fija.','B','trim() quita espacios en los extremos, no altera los internos.'),(670,31,'¿Qué instrucción debe ser la primera dentro de un constructor si deseas encadenar a otro constructor de la misma clase?','return;','super();','this(...);','break;','C','this(...) debe ser la primera sentencia para encadenar constructores dentro de la misma clase.'),(671,31,'Si existen sobrecargas f(int) y f(int...), ¿cuál se elige al invocar f(3)?','Siempre f(int...) por ser más flexible.','Siempre f(int) por ser más específica.','No compila por ambigüedad.','Depende del sistema operativo.','B','El compilador prefiere la coincidencia más específica: la versión exacta f(int).'),(672,31,'¿Qué significa marcar un campo con la combinación static final?','Se crea una variable por instancia.','Es una constante de clase: única y no reasignable.','Solo visible dentro del paquete.','Se inicializa en cada constructor.','B','static final define una constante de clase: compartida y cuyo valor no puede reasignarse.'),(673,31,'En una cadena if / else if / else, cuando una condición resulta verdadera:','Se ejecutan todos los bloques siguientes.','Se ejecuta su bloque y se omiten los siguientes.','Se evalúan las siguientes condiciones por si también son verdaderas.','Se lanza una advertencia del compilador.','B','Tras encontrar la primera condición verdadera, no se evalúan los else-if/else siguientes.'),(674,31,'¿Qué ocurre si intentas declarar dos constructores con la misma lista de parámetros?','Es válido si cambias el nombre del constructor.','No compila: la firma sería idéntica.','Es válido si cambias el tipo de retorno.','Es válido si cambias los modificadores de acceso.','B','La sobrecarga se basa en la lista de parámetros; firmas idénticas causan error de compilación.'),(675,31,'¿Para qué se utiliza un bloque de inicialización estática (static { ... })?','Para ejecutar código una vez cuando la clase se carga.','Para ejecutar código cada vez que se llama a un método.','Para ejecutar código antes de compilar.','Para ejecutar código después de finalizar el programa.','A','Los bloques static corren una única vez al inicializar la clase.'),(676,31,'Respecto al paso de parámetros, ¿qué se pasa cuando el argumento es una referencia a objeto?','El objeto completo por copia.','Una referencia por valor (la copia de la referencia).','Un puntero por referencia con aliasing.','Un descriptor inmutable del objeto.','B','Se copia la referencia; dentro del método puedes modificar el objeto referenciado, pero no cambiar la referencia del llamador.'),(677,31,'¿Qué característica tiene un campo estático (static) en una clase?','Pertenece a cada instancia por separado.','Pertenece a la clase y es compartido por todas las instancias.','Solo es accesible desde métodos de instancia.','Se destruye al salir de un método.','B','Los miembros static son de la clase, compartidos por todas las instancias.'),(678,31,'¿Qué sucede si colocas código antes de this(...) dentro de un constructor que encadena a otro?','Funciona pero ignora las líneas previas.','No compila: this(...) debe ser la primera sentencia.','Se ejecuta después del this(...).','Se convierte en un bloque static automáticamente.','B','El encadenamiento con this(...) debe ser la primera instrucción del constructor.'),(679,31,'¿Cuándo se ejecuta un bloque de inicialización de instancia ({ ... } sin static)?','Al compilar.','Cada vez que se crea una instancia, antes del constructor.','Una única vez por clase.','Solo si hay herencia múltiple.','B','Se ejecuta en cada construcción de objeto, previo al cuerpo del constructor.'),(680,31,'En switch clásico con case y break, ¿qué deben ser las etiquetas case?','Expresiones boolean evaluadas en tiempo de ejecución.','Expresiones constantes compatibles con el tipo del switch.','Cadenas generadas dinámicamente.','Cualquier expresión aritmética.','B','Las etiquetas case deben ser constantes en tiempo de compilación y del tipo compatible.'),(681,31,'Para diseñar una clase inmutable simple, ¿qué práctica ayuda?','Campos privados y finales, sin setters y construcción completa por constructor.','Campos públicos y mutables para flexibilidad.','Un setter por cada campo.','Constructores vacíos y cambios posteriores vía setters.','A','Inmutabilidad: campos private final, no exponer mutadores y establecer estado en el constructor.'),(682,31,'En un for tradicional (for inicialización; condición; actualización), ¿cuándo se evalúa la condición?','Solo antes de la primera iteración.','Antes de cada iteración.','Después de cada iteración.','Nunca; se asume verdadera.','B','La condición se verifica antes de cada vuelta; si es falsa, el bucle termina.'),(683,31,'¿Qué ocurre si en un bucle for omites la sección de inicialización y actualización (dejándolas vacías)?','No compila: son obligatorias.','Compila y puedes controlar el índice manualmente dentro del cuerpo.','El for se ejecuta exactamente una vez.','El for se convierte en while(true).','B','La sintaxis permite secciones vacías; es responsabilidad del programador manejar el avance del bucle.'),(684,31,'¿Qué afirmación es correcta sobre super(...) en un constructor?','Puede ir después de ejecutar otras sentencias.','Debe ser la primera sentencia si se usa en el constructor.','Solo puede invocarse desde métodos estáticos.','Es opcional y se inserta dos veces por el compilador.','B','super(...) debe ir primero si se invoca; si no se especifica, el compilador inserta super() implícitamente.'),(685,31,'Si un parámetro de método tiene el mismo nombre que un campo, ¿cómo se accede al campo?','Con el nombre directamente.','Usando super.campo','Usando this.campo','No es posible acceder al campo.','C','this.campo distingue el campo de instancia del parámetro sombreado.'),(686,31,'Para una propiedad no booleana llamada nombre, ¿cuál es la pareja getter/setter recomendada?','isNombre()/setNombre()','getNombre()/putNombre()','getNombre()/setNombre()','fetchNombre()/setNombre()','C','La convención JavaBeans usa getX()/setX() para propiedades no booleanas.'),(687,31,'¿Qué efecto tiene declarar un constructor como private?','La clase no puede contener métodos públicos.','Impide la instanciación desde fuera de la clase.','Convierte automáticamente la clase en final.','Obliga a tener al menos otro constructor public.','B','Un constructor private restringe la creación de instancias al interior de la propia clase.'),(688,31,'¿Qué efecto tiene marcar un método como final?','Evita que el método sea sobrecargado.','Evita que el método sea sobrescrito en subclases.','Convierte el método en estático.','Hace que el método sea privado.','B','final en métodos impide el overriding por parte de subclases.'),(689,31,'Según JavaBeans, ¿cuál es el getter recomendado para un campo boolean activo?','getActivo()','isActivo()','hasActivo()','getIsActivo()','B','Para boolean, la convención es usar isNombreCampo() como getter.'),(690,31,'¿Qué realiza Arrays.fill(arreglo, valor)?','Ordena el arreglo en sitio.','Rellena todas las posiciones del arreglo con el valor dado.','Elimina duplicados del arreglo.','Concatena el arreglo con otro del mismo tipo.','B','Asigna el mismo valor a todas las posiciones del arreglo especificado.'),(691,31,'¿Qué hace break etiqueta; en bucles anidados cuando la etiqueta está en el bucle externo?','Termina solo el bucle interno.','No compila: no existen etiquetas en Java.','Sale directamente del bucle etiquetado (externo).','Pausa la ejecución hasta nueva orden.','C','break con etiqueta rompe el bucle asociado, útil para salir de múltiples niveles.'),(692,31,'¿Cuál es el orden de inicialización típico al crear una instancia?','Constructor → bloques static → bloques de instancia','Bloques static → bloques de instancia → constructor','Bloques de instancia → bloques static → constructor','Constructor → bloques de instancia → bloques static','B','Primero se inicializa la clase (static), luego la instancia (bloques de instancia/campos) y por último el constructor.'),(693,31,'Con un arreglo, ¿qué limitación existe al usar for-each?','No permite recorrer arreglos vacíos.','No puedes conocer el índice directamente.','No puedes usar break.','No puedes leer elementos.','B','El for-each no expone el índice; si lo necesitas, usa un for con índice.'),(694,31,'En Java, el valor null representa…','Un número cero de tipo long.','Una referencia que no apunta a ningún objeto.','Un objeto vacío especial con métodos limitados.','Una cadena vacía de longitud cero.','B','null indica ausencia de referencia a objeto; no es una instancia ni una cadena vacía.'),(695,31,'En un método void, ¿qué implica ejecutar la sentencia return;?','Devuelve null al invocador.','Finaliza el método inmediatamente sin devolver un valor.','Reinicia la ejecución del método desde el inicio.','Devuelve un valor por defecto según el tipo primitivo.','B','En métodos void, return; sirve para salir de forma anticipada sin valor de retorno.'),(696,31,'Para objetos String en Java, ¿cuál es la diferencia entre \'==\' y equals()?','\'==\' compara referencias; equals() compara contenido.','\'==\' compara longitud; equals() compara codificación.','No hay diferencia: ambos comparan contenido.','\'==\' invoca intern() automáticamente.','A','\'==\' verifica si son la misma referencia; equals() determina si las secuencias de caracteres son iguales.'),(697,31,'¿Cuál firma es válida para un método que no devuelve valor y recibe un int y un String?','procesar(a, b)','void procesar(int a, String b)','int procesar(void)','function procesar(int a, String b)','B','La sintaxis correcta en Java incluye el tipo de retorno void y la lista de parámetros tipados.'),(698,31,'Respecto al alcance (scope), ¿qué ocurre con una variable declarada dentro de un bloque { }?','Solo es accesible dentro de ese bloque.','Permanece accesible en todo el método.','Se convierte en una variable global.','Se elimina en tiempo de compilación y no existe en ejecución.','A','Las variables locales de bloque solo existen y son visibles dentro del bloque donde se declaran.'),(699,31,'¿Cuál es la principal diferencia entre una variable y una constante en la ejecución de un programa?','La variable ocupa espacio en memoria RAM y la constante no.','El valor de la variable puede cambiar, mientras que el de la constante permanece inalterado tras su asignación.','Las variables solo almacenan números y las constantes solo texto.','Las constantes se declaran dentro de los ciclos y las variables fuera de ellos.','B','Por definición, una constante protege un valor durante todo el ciclo de vida del programa, mientras que la variable está diseñada para ser reasignada según la lógica del algoritmo.'),(700,31,'¿Cuál de las siguientes declaraciones crea un arreglo para tres referencias de Persona?','Persona personas = new Persona[3];','Persona[] personas = new Persona[3];','new Persona[3] personas;','Persona[3] personas = new Persona[];','B','La forma correcta es Tipo[] nombre = new Tipo[tamaño]; esto crea el arreglo de referencias.'),(701,31,'¿Qué palabra clave impide que una clase sea heredada?','abstract','final','static','sealed','B','final en una clase evita que otras clases la extiendan. (sealed existe en versiones modernas con reglas distintas).'),(702,31,'¿Cuál es el valor por defecto de una variable de instancia de tipo int si no se inicializa explícitamente?','undefined','0','null','Depende del constructor','B','Los campos de instancia numéricos primitivos se inicializan por defecto a 0; las variables locales deben inicializarse antes de usarse.'),(703,31,'La palabra clave this en un método de instancia hace referencia a…','La clase actual como tipo.','El paquete donde se ubica la clase.','La instancia actual del objeto que ejecuta el método.','La superclase inmediata.','C','this es la referencia al objeto receptor en el contexto actual.'),(704,31,'Dado un método calcular(int x), ¿cuál de las siguientes es una sobrecarga válida?','int calcular(int y) throws Exception','double calcular(int x)','void calcular()','calcular(int x)','C','Para sobrecargar se debe cambiar la lista de parámetros. Cambiar solo el tipo de retorno (opción B) no sobrecarga; \'throws\' no afecta la firma para overloading.'),(705,31,'¿Qué nivel de acceso tiene un miembro sin modificador explícito (default)?','private','public','protected','package-private (visible solo dentro del mismo paquete)','D','El acceso por defecto en Java es de paquete: visible para clases del mismo paquete.'),(706,31,'Si necesitas acceso rápido por índice y sueles añadir elementos al final, ¿qué implementación de List conviene más?','LinkedList','ArrayList','Vector','Stack','B','ArrayList ofrece acceso O(1) promedio por índice y apéndices amortizados eficientes; LinkedList favorece inserciones/remociones en medio.'),(707,31,'Para comparar por igualdad lógica dos instancias de una clase Persona en una lista, lo más apropiado es…','Usar \'==\' para comparar campos uno a uno.','Sobrescribir equals y hashCode de forma coherente en Persona.','Convertir las personas a String y comparar las cadenas.','Utilizar System.identityHashCode para comparar.','B','equals/hashCode permiten definir igualdad lógica y comportarse correctamente en colecciones.'),(708,31,'¿Qué llamada convierte correctamente un String en un int?','Integer.valueOf(s).intValue()','Integer.parseInt(s)','int.parse(s)','Parse.toInt(s)','B','Integer.parseInt devuelve un primitivo int a partir de un String numérico válido.'),(709,31,'¿Cuál de las siguientes es una excepción verificada (checked) en Java?','NullPointerException','ArrayIndexOutOfBoundsException','IOException','ArithmeticException','C','IOException es checked y debe declararse o manejarse; las otras son unchecked (RuntimeException).'),(710,31,'¿Cuál es el índice del primer elemento en un arreglo en Java?','1','Depende del tipo del arreglo.','0','-1','C','En Java, los arreglos son indexados desde 0.'),(711,31,'¿Cuándo es más adecuado usar un bucle for-each (for : ) sobre un arreglo o lista?','Cuando necesitas modificar el índice durante la iteración.','Cuando solo lees los elementos en orden y no necesitas el índice.','Cuando necesitas eliminar elementos mientras iteras con seguridad.','Cuando no conoces el tipo de los elementos.','B','El for-each simplifica la lectura secuencial sin exponer el índice ni permitir modificar la colección.'),(712,31,'¿Qué tipo es más adecuado para representar cantidades monetarias con precisión exacta en Java básico?','double','float','java.math.BigDecimal','long','C','Para cálculos con precisión decimal exacta se usa BigDecimal; double y float son binarios y pueden introducir errores de redondeo, y long es entero.'),(713,31,'¿Cuál es la diferencia práctica entre StringBuilder y StringBuffer?','StringBuilder es sincronizado y más lento; StringBuffer no lo es.','StringBuffer es inmutable y StringBuilder mutable.','StringBuilder no es sincronizado y suele ser más rápido en un solo hilo; StringBuffer es sincronizado.','No hay diferencias: son equivalentes.','C','StringBuffer sincroniza operaciones (útil en concurrencia), StringBuilder evita esa sobrecarga en contextos de un solo hilo.'),(714,31,'En POO, la encapsulación se refiere a…','Heredar comportamiento de múltiples clases.','Ocultar el estado interno y exponerlo mediante métodos controlados (getters/setters).','Convertir tipos primitivos en objetos automáticamente.','Compartir variables entre hilos.','B','Encapsular implica restringir el acceso directo a los datos y proveer métodos de acceso para mantener invariantes.'),(715,31,'¿Qué estructura de la biblioteca estándar mantiene orden por índice y permite elementos duplicados?','HashSet','TreeSet','ArrayList','HashMap','C','ArrayList es una lista basada en array dinámico, indexada y admite duplicados; los Set no permiten duplicados.'),(716,31,'¿Cuál es la diferencia principal entre una clase y un objeto en Java?','La clase es una plantilla y el objeto es una instancia concreta creada a partir de ella.','La clase ocupa memoria en el heap y el objeto no.','El objeto define comportamientos y la clase solo datos.','No hay diferencia: ambos términos son sinónimos.','A','Una clase modela la estructura y comportamiento; un objeto es una realización específica con estado propio basada en esa clase.'),(717,31,'El operador ternario (cond ? a : b) sirve para…','Crear dos hilos y escoger cuál corre.','Evaluar una condición y seleccionar entre dos expresiones.','Concatenar cadenas de forma perezosa.','Generar excepciones personalizadas.','B','El operador condicional devuelve a si la condición es verdadera o b en caso contrario.'),(718,31,'La sobrescritura de métodos (overriding) ocurre cuando…','Una clase define múltiples métodos con el mismo nombre y distinta lista de parámetros.','Una subclase define un método con la misma firma y un comportamiento distinto al de la superclase.','Se cambia el tipo de retorno de un método estático.','Se llama a un método privado desde otra clase.','B','Overriding requiere herencia y la misma firma para redefinir el comportamiento.'),(719,31,'Respecto a switch en versiones modernas de Java, ¿es posible usar String como expresión?','Sí, se puede usar String y se compara por contenido.','No, solo se permiten tipos numéricos primitivos.','Sí, pero únicamente si el String está internado manualmente.','Solo en clases abstractas.','A','Desde Java 7 se pueden usar String en switch, comparando según equals().'),(720,31,'Respecto a String en Java, es correcto afirmar que…','Es mutable para mejorar el rendimiento.','Es inmutable; cualquier modificación crea un nuevo objeto.','Es un tipo primitivo especial del lenguaje.','No se puede usar en colecciones.','B','String es inmutable por diseño, lo que favorece la seguridad y el cacheo de literales.'),(721,31,'Tras ejecutar Persona[] p = new Persona[3]; ¿qué hay en p[0]?','Una instancia Persona creada con el constructor por defecto.','Una referencia null.','Una referencia no inicializada que causa error de compilación.','Un objeto vacío con valores por defecto.','B','El arreglo de referencias contiene null hasta que se asigne explícitamente new Persona() a cada posición.'),(722,31,'¿Cuál es el resultado de 5 / 2 cuando ambos operandos son int en Java?','2.5','2','3','Depende de la JVM','B','La división entre enteros descarta la parte fraccionaria, resultando 2.'),(723,31,'La sobrecarga de métodos (overloading) en Java se basa en…','Cambiar el nombre del método manteniendo parámetros.','Cambiar la lista de parámetros (número o tipos).','Cambiar solo el tipo de retorno.','Cambiar solo los modificadores de acceso.','B','Dos métodos están sobrecargados si comparten nombre pero difieren en la lista de parámetros.'),(724,31,'¿Qué modificador indica que un método pertenece a la clase y no a la instancia?','final','static','abstract','native','B','static asocia el método a la clase; puede invocarse sin crear un objeto.'),(725,31,'¿Qué modificador de acceso limita el uso de un miembro exclusivamente a su propia clase?','public','protected','(sin modificador) / package-private','private','D','private restringe el acceso al miembro únicamente dentro de la clase donde se declara.'),(726,31,'¿Qué hace la palabra clave new en Java?','Declara una nueva clase en tiempo de ejecución.','Crea una instancia de una clase y reserva memoria para ella.','Importa un paquete al espacio de nombres actual.','Convierte un tipo primitivo a su wrapper automáticamente.','B','new construye un objeto, invoca su constructor y reserva la memoria necesaria en el heap.'),(727,31,'¿Cómo se declara correctamente una constante pública de clase en Java?','public const int MAX = 10;','public static final int MAX = 10;','public final int MAX = 10;','public static const int MAX = 10;','B','Las constantes de clase se declaran con static final; no existe la palabra clave const en Java.'),(728,31,'¿Qué bucle es más adecuado cuando conoces de antemano el número exacto de iteraciones?','for clásico (for inicialización; condición; actualización)','while','do-while','foreach','A','El for clásico expresa naturalmente conteos definidos con un índice.'),(729,31,'La palabra clave super permite…','Acceder a miembros estáticos sin calificación.','Referirse a miembros de la superclase o invocar su constructor.','Crear objetos sin usar new.','Elevar privilegios de acceso a private.','B','super refiere a la superclase para acceder a sus miembros no privados o llamar a su constructor.'),(730,31,'Si no defines ningún constructor en una clase, ¿qué sucede?','El compilador genera un constructor por defecto sin parámetros.','La clase no puede instanciarse.','Se crea un constructor privado automáticamente.','El compilador exige definir al menos uno público.','A','Si no hay constructores declarados, se provee uno por defecto sin argumentos y con visibilidad de la clase.'),(731,31,'Si necesitas una colección que evite duplicados sin importar el orden, ¿cuál usarías?','ArrayList','LinkedList','HashSet','PriorityQueue','C','Un Set (como HashSet) no permite duplicados y no garantiza un orden específico.'),(732,31,'¿Cómo se declara y crea un arreglo de 10 enteros en Java?','int a = new int(10);','int[] a = new int[10];','int a[] = {10};','array<int> a = new array<int>(10);','B','La sintaxis correcta para arreglos es tipo[] nombre = new tipo[tamaño];'),(733,31,'En una sentencia switch en Java, si se omite la palabra clave break en un caso, ¿qué ocurre?','Se lanza automáticamente una excepción de tipo IllegalStateException.','El control termina el switch inmediatamente.','Se produce \'fall-through\' y continúa ejecutando el siguiente caso hasta encontrar un break o terminar el switch.','El compilador impide compilar el código.','C','Sin break, el flujo cae al siguiente case (fall-through) ejecutando sus sentencias consecutivas.'),(734,32,'¿Qué valor toma la variable resultado?\nSi 14 % 2 == 0 Entonces\n    resultado <- \'Par\'\nSino\n    resultado <- \'Impar\'\nFinSi','No cambia','Cero','Par','Error','C','Porque 14 % 2 es 0, la condición determina que el número es \'Par\'.'),(735,32,'¿Cuántas veces se ejecuta el cuerpo de un ciclo si inicia en i = 1 y repite mientras i < 5, aumentando i en 1 cada vez?','Es un bucle infinito','5 veces','3 veces','4 veces','D','Con i < 5, las iteraciones ocurren para i = 1, 2, 3 y 4. Cuando i llega a 5, la condición deja de cumplirse.'),(736,32,'¿Qué es la indentación (sangría) y por qué es importante?','Es una función para imprimir en pantalla.','Es un método para encriptar contraseñas.','Es el espacio al inicio de las líneas para indicar qué bloques de código pertenecen a otros.','Es un tipo de variable para textos largos.','C','La indentación mejora la legibilidad y, en lenguajes como Python, es obligatoria para definir la jerarquía del código.'),(737,32,'En un ciclo anidado (dos niveles), ¿qué efecto tiene \'romper\' (break) en el ciclo interno?','No tiene efecto en ningún ciclo.','Detiene ambos ciclos siempre.','Solo detiene el ciclo interno; el externo continúa con su siguiente iteración.','Reinicia el programa desde el inicio.','C','El \'break\' afecta el ciclo donde se ejecuta; el externo sigue según su propia condición.'),(738,32,'¿Cuál es el objetivo de usar una variable bandera (flag) en un algoritmo?','Controlar el formato de impresión.','Forzar la salida de todos los ciclos.','Incrementar un contador automáticamente.','Recordar si cierto evento/condición ya ocurrió para tomar decisiones posteriores.','D','Las banderas almacenan estados lógicos (verdadero/falso) para guiar el flujo según eventos previos.'),(739,32,'¿Qué es una \'Prueba de Escritorio\'?','Seguir manualmente los pasos de un algoritmo con valores de ejemplo para verificar el resultado.','Limpiar el lugar de trabajo del programador.','Un examen para comprar una computadora nueva.','Instalar el software en la PC del cliente.','A','Es la técnica manual para validar la lógica antes de programar, simulando cómo cambiarían las variables paso a paso.'),(740,32,'¿Cuál es el resultado de evaluar la condición ( 10 * 2 > 7 + 1 ) en pseudocódigo?','0','Error','No se puede','Verdadero','D','Se aplica lógica matemática simple comparando ambas expresiones numéricas.'),(741,32,'¿Cuál es el resultado de evaluar la condición ( 1 * 2 > 7 + 1 ) en pseudocódigo?','Error','0','No se puede','Falso','D','Se aplica lógica matemática simple comparando ambas expresiones numéricas.'),(742,32,'¿Cuál es el resultado de evaluar la condición ( 5 * 2 > 4 + 1 ) en pseudocódigo?','No se puede','Verdadero','0','Error','B','Se aplica lógica matemática simple comparando ambas expresiones numéricas.'),(743,32,'Si la regla es: si nota >= 3.0 entonces \'Aprueba\', en caso contrario \'Reprueba\', ¿qué sucede cuando nota = 3.0?','Se salta la condición y no muestra nada','Reprueba','Da error porque 3.0 no es válido','Aprueba','D','El operador >= incluye el límite. Si nota es exactamente 3.0, la condición se cumple y se ejecuta la rama de aprobación.'),(744,32,'¿Cuál es el resultado de evaluar la condición ( 6 * 2 > 9 + 1 ) en pseudocódigo?','Verdadero','0','Error','No se puede','A','Se aplica lógica matemática simple comparando ambas expresiones numéricas.'),(745,32,'¿Para qué sirve el tipo de dato \'Booleano\'?','Para representar valores de lógica binaria: Verdadero o Falso.','Para listas de nombres.','Para almacenar números con muchos decimales.','Para guardar fechas y horas.','A','Es el tipo de dato más simple y fundamental para la toma de decisiones en condicionales.'),(746,32,'¿Cuál es el resultado de evaluar la condición ( 7 * 2 > 4 + 1 ) en pseudocódigo?','No se puede','Verdadero','0','Error','B','Se aplica lógica matemática simple comparando ambas expresiones numéricas.'),(747,32,'¿Cuántas veces puede ejecutarse este ciclo?\ni <- 0\nRepetir\n    i <- i + 1\nHasta Que i == 13','13','15','Depende del lenguaje','12','A','El ciclo incrementa i hasta llegar a 13, por lo que se ejecuta 13 veces.'),(748,32,'¿Cuál es el resultado de evaluar la condición ( 10 * 2 > 8 + 1 ) en pseudocódigo?','0','Verdadero','No se puede','Error','B','Se aplica lógica matemática simple comparando ambas expresiones numéricas.'),(749,32,'¿Cuántas veces se ejecuta el siguiente ciclo?\nPara i = 1 Hasta 4 Con Paso 1 Hacer\n    Mostrar i\nFinPara','4','5','3','No se puede determinar','A','El ciclo inicia en 1 y termina en 4, avanzando de 1 en 1, por lo que se ejecuta 4 veces.'),(750,32,'Si necesitas guardar el resultado de 7 / 2 como 3.5 (con decimales), ¿qué tipo de dato es más adecuado para la variable resultado?','Flotante/Decimal (Float/Double)','Booleano (Boolean)','Carácter (Char)','Entero (Integer)','A','Un tipo flotante permite representar valores con parte decimal. Con enteros, muchas veces la división se trunca y se pierde la parte decimal.'),(751,32,'¿Cuántas veces puede ejecutarse este ciclo?\ni <- 0\nRepetir\n    i <- i + 1\nHasta Que i == 7','Depende del lenguaje','6','7','9','C','El ciclo incrementa i hasta llegar a 7, por lo que se ejecuta 7 veces.'),(752,32,'¿Qué valor toma la variable resultado?\nSi 1 % 2 == 0 Entonces\n    resultado <- \'Par\'\nSino\n    resultado <- \'Impar\'\nFinSi','No cambia','Impar','Error','Cero','B','Porque 1 % 2 es 1, la condición determina que el número es \'Impar\'.'),(753,32,'¿Qué valor toma la variable resultado?\nSi 15 % 2 == 0 Entonces\n    resultado <- \'Par\'\nSino\n    resultado <- \'Impar\'\nFinSi','Impar','Cero','Error','No cambia','A','Porque 15 % 2 es 1, la condición determina que el número es \'Impar\'.'),(754,32,'¿Qué es un ciclo en programación?','Una estructura que compara dos valores','Una forma de declarar variables','Una función que almacena datos','Una estructura que repite un bloque de instrucciones mientras se cumpla una condición','D','Un ciclo permite repetir instrucciones de forma controlada basándose en condiciones.'),(755,32,'¿Cuál es el resultado de evaluar la condición ( 8 * 2 > 3 + 1 ) en pseudocódigo?','Verdadero','No se puede','Error','0','A','Se aplica lógica matemática simple comparando ambas expresiones numéricas.'),(756,32,'¿Qué valor toma la variable resultado?\nSi 4 % 2 == 0 Entonces\n    resultado <- \'Par\'\nSino\n    resultado <- \'Impar\'\nFinSi','Par','Error','No cambia','Cero','A','Porque 4 % 2 es 0, la condición determina que el número es \'Par\'.'),(757,32,'Si \'Verdadero AND Falso\' es evaluado en un algoritmo, ¿cuál es el resultado?','Error','Cero','Falso','No se puede evaluar','C','Aplicación de reglas básicas de lógica proposicional en programación.'),(758,32,'¿Cuántas veces puede ejecutarse este ciclo?\ni <- 0\nRepetir\n    i <- i + 1\nHasta Que i == 12','14','12','Depende del lenguaje','11','B','El ciclo incrementa i hasta llegar a 12, por lo que se ejecuta 12 veces.'),(759,32,'¿Cuál es el resultado de evaluar la condición ( 8 * 2 > 1 + 1 ) en pseudocódigo?','Verdadero','Error','No se puede','0','A','Se aplica lógica matemática simple comparando ambas expresiones numéricas.'),(760,32,'¿Qué es un comentario en el código?','Una variable que guarda opiniones.','Una instrucción que el usuario lee en pantalla.','Texto ignorado por el compilador usado para explicar la lógica a otros humanos.','Un mensaje de error del sistema.','C','Los comentarios son vitales para el mantenimiento del código, permitiendo que otros programadores entiendan qué se intentó hacer.'),(761,32,'En una cadena de \'si - sino si - sino\', ¿cuándo se ejecuta el bloque \'sino\'?','Cuando alguna condición intermedia es verdadera.','Siempre, después del primer \'si\'.','Solo si todas las condiciones anteriores fueron falsas.','Cuando la primera condición es verdadera.','C','\'sino\' actúa como caso por defecto: se ejecuta si ninguna condición previa fue verdadera.'),(762,32,'¿Qué tipo de dato devolvería la comparación (10 == \'10\') en un lenguaje con tipado estricto?','Nulo (Null)','1010','Verdadero (True)','Falso (False) o Error','D','En tipado estricto, un Entero y una Cadena de texto son tipos diferentes, por lo que la comparación falla aunque el contenido \'parezca\' igual.'),(763,32,'¿Cuál es el resultado de evaluar la condición ( 3 * 2 > 5 + 1 ) en pseudocódigo?','No se puede','Falso','0','Error','B','Se aplica lógica matemática simple comparando ambas expresiones numéricas.'),(764,32,'¿Cuántas veces se ejecuta el siguiente ciclo?\nPara i = 1 Hasta 9 Con Paso 1 Hacer\n    Mostrar i\nFinPara','8','10','No se puede determinar','9','D','El ciclo inicia en 1 y termina en 9, avanzando de 1 en 1, por lo que se ejecuta 9 veces.'),(765,32,'¿Cuál es el resultado de evaluar la condición ( 9 * 2 > 4 + 1 ) en pseudocódigo?','Error','Verdadero','No se puede','0','B','Se aplica lógica matemática simple comparando ambas expresiones numéricas.'),(766,32,'¿Qué resultado arroja la expresión lógica: (5 > 3) AND (10 < 8)?','Error de sintaxis','True','15','False','D','En una operación AND, ambas condiciones deben ser verdaderas. Aunque (5 > 3) es verdadero, (10 < 8) es falso, invalidando toda la expresión.'),(767,32,'¿Cuál es el resultado de evaluar la condición ( 4 * 2 > 2 + 1 ) en pseudocódigo?','0','Error','Verdadero','No se puede','C','Se aplica lógica matemática simple comparando ambas expresiones numéricas.'),(768,32,'Dada la expresión lógica: NOT(True AND False) OR False, ¿cuál es el resultado?','Depende del lenguaje','True','Indeterminado','False','B','True AND False = False; NOT(False) = True; True OR False = True.'),(769,32,'¿Cuál de estos es un error de lógica y no de sintaxis?','Escribir \'whle\' en lugar de \'while\'.','No cerrar un paréntesis.','Calcular el promedio dividiendo la suma por un número incorrecto de elementos.','Olvidar un punto y coma.','C','Los errores de sintaxis impiden que el programa corra. Los de lógica permiten que corra, pero dan resultados incorrectos.'),(770,32,'¿Cuántas veces se ejecuta el siguiente ciclo?\nPara i = 1 Hasta 10 Con Paso 1 Hacer\n    Mostrar i\nFinPara','10','9','No se puede determinar','11','A','El ciclo inicia en 1 y termina en 10, avanzando de 1 en 1, por lo que se ejecuta 10 veces.'),(771,32,'¿Qué es un \'Contador\' en programación?','Una función que mide el tiempo de ejecución.','Un tipo de dato especial para finanzas.','Una variable que se incrementa o decrementa en un valor constante (usualmente 1).','Una variable que guarda la suma de valores variables.','C','Los contadores se usan para llevar el registro de iteraciones (ej: i = i + 1).'),(772,32,'¿Cuál es el primer paso recomendado antes de escribir el código de un algoritmo complejo?','Compilar el programa.','Realizar un análisis del problema y diseñar un diagrama de flujo o pseudocódigo.','Comprar una licencia de un lenguaje de programación.','Definir las variables globales en la base de datos.','B','La planeación mediante pseudocódigo evita errores de lógica estructural que son difíciles de corregir una vez codificados.'),(773,32,'¿Cuál es el propósito del operador módulo (%) en programación?','Calcular el porcentaje de un número.','Elevar un número a una potencia.','Obtener el residuo o resto de una división entera.','Dividir dos números y devolver el cociente entero.','C','El módulo es fundamental para lógica de ciclos y condicionales, como determinar si un número es par (n % 2 == 0).'),(774,32,'¿Qué valor toma la variable resultado?\nSi 11 % 2 == 0 Entonces\n    resultado <- \'Par\'\nSino\n    resultado <- \'Impar\'\nFinSi','Cero','Error','Impar','No cambia','C','Porque 11 % 2 es 1, la condición determina que el número es \'Impar\'.'),(775,32,'¿Cuál es el resultado de la concatenación de \'Hola\' + \'Mundo\'?','Error: no se pueden sumar palabras.','Hola Mundo','2','HolaMundo','D','La concatenación une las cadenas tal cual están. Si no hay un espacio dentro de las comillas, los textos se pegan directamente.'),(776,32,'¿Qué valor toma la variable resultado?\nSi 7 % 2 == 0 Entonces\n    resultado <- \'Par\'\nSino\n    resultado <- \'Impar\'\nFinSi','No cambia','Error','Cero','Impar','D','Porque 7 % 2 es 1, la condición determina que el número es \'Impar\'.'),(777,32,'¿Qué valor toma la variable resultado?\nSi 16 % 2 == 0 Entonces\n    resultado <- \'Par\'\nSino\n    resultado <- \'Impar\'\nFinSi','No cambia','Error','Cero','Par','D','Porque 16 % 2 es 0, la condición determina que el número es \'Par\'.'),(778,32,'¿Para qué sirve la estructura \'Switch\' o \'Según sea\'?','Para conectar la base de datos.','Para declarar variables globales.','Para repetir un bloque de código muchas veces.','Para manejar múltiples condiciones basadas en el valor de una sola expresión.','D','Es una alternativa más limpia a múltiples \'If-Else\' anidados cuando se evalúa una misma variable contra varios valores posibles.'),(779,32,'¿Cuál es el valor de la variable \'x\' tras ejecutar: x = 10; x = x + 5; x = x * 2;?','20','15','25','30','D','Sigue un orden secuencial: 10 + 5 = 15; luego 15 * 2 = 30.'),(780,32,'¿Cuántas veces se ejecuta el siguiente ciclo?\nPara i = 1 Hasta 5 Con Paso 1 Hacer\n    Mostrar i\nFinPara','No se puede determinar','5','6','4','B','El ciclo inicia en 1 y termina en 5, avanzando de 1 en 1, por lo que se ejecuta 5 veces.'),(781,32,'¿Cuál es el resultado de evaluar la condición ( 8 * 2 > 9 + 1 ) en pseudocódigo?','0','No se puede','Verdadero','Error','C','Se aplica lógica matemática simple comparando ambas expresiones numéricas.'),(782,32,'¿Cuál es la principal característica del ciclo \'While\'?','Se ejecuta al menos una vez, sin importar la condición.','Se ejecuta un número exacto de veces definido al inicio.','Solo se utiliza para recorrer arreglos.','Se ejecuta mientras una condición sea verdadera, evaluándola antes de cada iteración.','D','El \'While\' es un ciclo de pre-condición. Si la condición es falsa desde el principio, el bloque de código nunca se ejecuta.'),(783,32,'En un \'según sea\' (switch) con casos 1, 2, 3 y un caso por defecto, si la variable vale 4, ¿qué bloque se ejecuta?','El caso 2','El caso 1','El caso 3','El caso por defecto','D','Al no coincidir 4 con ningún caso explícito, se ejecuta el bloque por defecto.'),(784,32,'En pseudocódigo: contador = 0; para i desde 1 hasta 5 hacer: si i % 2 == 0 entonces contador = contador + 1. ¿Cuál es el valor final de contador?','3','1','4','2','D','Los pares entre 1 y 5 son 2 y 4; se cuentan 2 valores.'),(785,32,'¿Cuál es el resultado de evaluar la condición ( 7 * 2 > 5 + 1 ) en pseudocódigo?','0','No se puede','Verdadero','Error','C','Se aplica lógica matemática simple comparando ambas expresiones numéricas.'),(786,32,'¿Cuántas veces puede ejecutarse este ciclo?\ni <- 0\nRepetir\n    i <- i + 1\nHasta Que i == 14','13','Depende del lenguaje','14','16','C','El ciclo incrementa i hasta llegar a 14, por lo que se ejecuta 14 veces.'),(787,32,'Se desea encontrar el primer número mayor que 0 en una lista. ¿Qué control de flujo es más adecuado?','Usar únicamente condicionales anidados sin ciclos.','Usar un ciclo con una bandera (encontrado) y romper (break) al hallarlo.','Seguir recorriendo toda la lista aunque ya se encontró.','Sumar todos los números y dividir por la longitud.','B','Una bandera o una interrupción temprana optimiza el recorrido al detenerse cuando se cumple el objetivo.'),(788,32,'De acuerdo a las buenas prácticas (CamelCase), ¿cuál sería el nombre correcto para una variable que guarda el precio final de un producto?','precio_final','PRECIO_FINAL','PrecioFinal','precioFinal','D','CamelCase inicia con minúscula y cada palabra siguiente con mayúscula. La opción D (PascalCase) suele usarse para clases, y la A (SNAKE_CASE_MAYUS) para constantes.'),(789,32,'Si necesitas almacenar la cantidad de hijos de una persona, ¿cuál es el tipo de dato más adecuado?','Cadena (String)','Flotante (Float/Double)','Entero (Integer)','Booleano','C','La cantidad de hijos es una unidad discreta y contable que no admite decimales, por lo que un entero es el tipo de dato óptimo.'),(790,32,'¿Qué valor toma la variable resultado?\nSi 18 % 2 == 0 Entonces\n    resultado <- \'Par\'\nSino\n    resultado <- \'Impar\'\nFinSi','Par','Error','Cero','No cambia','A','Porque 18 % 2 es 0, la condición determina que el número es \'Par\'.'),(791,32,'Si edad = 17 y permisoEspecial = True, ¿qué resultado tiene la condición (edad >= 18) OR (permisoEspecial == True)?','Error de sintaxis','True','False','Depende del lenguaje, nunca se puede saber','B','En un OR basta con que una condición sea verdadera. Aunque edad >= 18 es falso, permisoEspecial == True es verdadero, así que toda la condición resulta verdadera.'),(792,32,'Si i inicia en 0 y se ejecuta un ciclo mientras i < 10, pero dentro del ciclo nunca se cambia i, ¿qué es lo más probable que ocurra?','El programa compila pero siempre salta el ciclo.','El ciclo se ejecuta 9 veces y se detiene.','El ciclo se ejecuta exactamente 10 veces.','El ciclo puede volverse infinito porque la condición nunca cambia.','D','Si i nunca se actualiza, seguirá siendo 0 y la condición i < 10 permanecerá verdadera, causando un bucle infinito.'),(793,32,'Si n = 1234 y se hace: contar = 0; mientras n > 0: n = n / 10 (entera); contar = contar + 1. ¿Qué valor tendrá \'contar\'?','4','2','3','5','A','Se eliminan dígitos enteros sucesivamente: 1234→123→12→1→0. Se cuentan 4 iteraciones.'),(794,32,'¿Qué es un \'Acumulador\'?','Un método para borrar la memoria.','Una variable que suma valores variables en cada iteración.','Una variable que siempre aumenta de 1 en 1.','Una estructura que guarda nombres de variables.','B','A diferencia del contador, el acumulador suma montos distintos (ej: total = total + precioArticulo).'),(795,32,'¿Cuál es el resultado de evaluar la condición ( 8 * 2 > 2 + 1 ) en pseudocódigo?','Verdadero','0','No se puede','Error','A','Se aplica lógica matemática simple comparando ambas expresiones numéricas.'),(796,32,'¿Cuál es el resultado de evaluar la condición ( 7 * 2 > 3 + 1 ) en pseudocódigo?','Error','No se puede','0','Verdadero','D','Se aplica lógica matemática simple comparando ambas expresiones numéricas.'),(797,32,'¿Cuál es la principal diferencia entre una variable y una constante en la ejecución de un programa?','La variable ocupa espacio en memoria RAM y la constante no.','Las variables solo almacenan números y las constantes solo texto.','Las constantes se declaran dentro de los ciclos y las variables fuera de ellos.','El valor de la variable puede cambiar, mientras que el de la constante permanece inalterado tras su asignación.','D','Por definición, una constante protege un valor durante todo el ciclo de vida del programa, mientras que la variable está diseñada para ser reasignada según la lógica del algoritmo.'),(798,32,'¿Cuál es el resultado de evaluar la condición ( 1 * 2 > 4 + 1 ) en pseudocódigo?','0','Falso','No se puede','Error','B','Se aplica lógica matemática simple comparando ambas expresiones numéricas.'),(799,32,'En lógica de programación, ¿qué representa el proceso de \'Inicialización\'?','Asignar un tipo de dato a una variable sin darle un valor.','Es el acto de borrar el contenido de la memoria caché.','Asignar un valor inicial a una variable antes de ser utilizada por primera vez.','El momento en que el código se traduce a lenguaje máquina.','C','Utilizar una variable sin inicializar suele provocar errores de \'basura en memoria\' o valores nulos (null/undefined), por lo que darle un valor inicial es una buena práctica esencial.'),(800,32,'En el contexto de ciclos, ¿qué es un \'Bucle Infinito\'?','Una estructura que usa demasiada memoria RAM.','Un ciclo diseñado para durar exactamente 24 horas.','Un error de lógica donde la condición de salida nunca se vuelve falsa.','Un ciclo que procesa grandes cantidades de datos.','C','Si la variable de control nunca cambia o la condición siempre es verdadera, el programa queda atrapado, consumiendo recursos sin finalizar.'),(801,32,'¿Cuántas veces puede ejecutarse este ciclo?\ni <- 0\nRepetir\n    i <- i + 1\nHasta Que i == 11','11','Depende del lenguaje','13','10','A','El ciclo incrementa i hasta llegar a 11, por lo que se ejecuta 11 veces.'),(802,32,'En muchos lenguajes, ¿qué diferencia práctica hay entre usar \'=\' y \'==\' dentro de una condición?','\'=\' compara dos valores y \'==\' asigna un valor a una variable.','Ambos operadores hacen exactamente lo mismo dentro de una condición.','\'==\' solo funciona con números y \'=\' solo con texto.','\'=\' se usa para asignar un valor, mientras que \'==\' se usa para comparar si dos valores son iguales.','D','En la mayoría de lenguajes, \'=\' realiza asignación y \'==\' realiza comparación. Confundirlos suele causar errores de lógica o de compilación según el lenguaje.'),(803,32,'¿Cuál es el resultado de evaluar la condición ( 9 * 2 > 6 + 1 ) en pseudocódigo?','Verdadero','Error','0','No se puede','A','Se aplica lógica matemática simple comparando ambas expresiones numéricas.'),(804,32,'¿Cuál es el resultado de la expresión: True OR False AND False (asumiendo que AND se evalúa antes que OR)?','Error de sintaxis','No se puede evaluar sin un ciclo','False','True','D','Primero se evalúa False AND False = False. Luego True OR False = True. La prioridad de operadores influye en el resultado.'),(805,32,'¿Qué valor final tiene \'i\' después de: i = 0; mientras i < 3: i = i + 1?','2','3','0','1','B','El ciclo ejecuta i=1, i=2, i=3; al llegar a 3 termina, quedando i en 3.'),(806,32,'¿Cuál es el resultado de evaluar la condición ( 6 * 2 > 4 + 1 ) en pseudocódigo?','Verdadero','Error','0','No se puede','A','Se aplica lógica matemática simple comparando ambas expresiones numéricas.'),(807,32,'En un ciclo \'For\', ¿cuáles son los tres elementos que suelen definirse en la cabecera?','Variable, Condición y Tipo de dato.','Nombre, Valor y Salida.','Inicialización, Condición e Incremento/paso.','Entrada, Proceso y Salida.','C','El ciclo \'For\' agrupa la inicialización del contador, la condición de permanencia y cómo cambia el contador en una sola línea.'),(808,32,'En un ciclo, ¿qué efecto tiene la instrucción \'continue\' (en los lenguajes que la soportan)?','Salta al inicio de la siguiente iteración, omitiendo el resto de instrucciones de la iteración actual.','Declara una variable para continuar el programa.','Repite la misma iteración sin volver a evaluar la condición.','Finaliza el ciclo por completo y sale de él.','A','\'continue\' no termina el ciclo; solo omite lo que falta de la iteración actual y vuelve al control del ciclo para seguir con la siguiente.'),(809,32,'En una división, ¿cuál afirmación describe mejor por qué a veces 5 / 2 da 2 y otras veces da 2.5?','Depende de si se usan números enteros o decimales: con enteros puede truncar y con decimales conserva la parte decimal.','Da error, porque no se puede dividir 5 entre 2.','Siempre da 2.5, porque toda división produce decimales.','Siempre da 2, porque el residuo se elimina en cualquier lenguaje.','A','La forma en que se calcula la división puede depender del tipo de dato. Con enteros, algunos lenguajes realizan división entera (truncada).'),(810,32,'Si un ciclo \'repetir hasta\' finaliza cuando suma >= 100, ¿qué característica tiene su condición de parada?','Se evalúa al final, por lo que el cuerpo se ejecuta al menos una vez.','Se evalúa al inicio del ciclo.','Depende del compilador.','No tiene condición de parada.','A','\'Repetir...hasta\' comprueba la condición al final, garantizando al menos una ejecución.'),(811,32,'¿Cuál es el resultado de evaluar la condición ( 2 * 2 > 4 + 1 ) en pseudocódigo?','No se puede','Falso','0','Error','B','Se aplica lógica matemática simple comparando ambas expresiones numéricas.'),(812,32,'¿Cuántas veces puede ejecutarse este ciclo?\ni <- 0\nRepetir\n    i <- i + 1\nHasta Que i == 15','Depende del lenguaje','15','14','17','B','El ciclo incrementa i hasta llegar a 15, por lo que se ejecuta 15 veces.'),(813,32,'¿Qué significa que un algoritmo sea \'Finito\'?','Que solo puede procesar números pequeños.','Que debe ser muy delgado al escribirse.','Que debe tener un número determinado de pasos y terminar en algún momento.','Que no puede ser traducido a otros idiomas.','C','Un proceso que no termina nunca no es un algoritmo funcional, es un error o un proceso infinito.'),(814,32,'Si se ejecuta: suma = 0; para i desde 2 hasta 10 paso 2: suma = suma + i. ¿Cuál es el valor de suma?','20','24','30','32','C','Se suman 2+4+6+8+10 = 30.'),(815,32,'Si total empieza en 0 y se lee precio hasta que sea -1 (sentinela), sumando cada precio válido, ¿qué condición del ciclo es correcta?','mientras precio != -1','siempre','repetir hasta precio != -1','mientras precio == -1','A','Se itera mientras el valor leído no sea el sentinela; cuando es -1, se detiene.'),(816,32,'¿Cuántas veces se ejecuta el siguiente ciclo?\nPara i = 1 Hasta 6 Con Paso 1 Hacer\n    Mostrar i\nFinPara','No se puede determinar','6','7','5','B','El ciclo inicia en 1 y termina en 6, avanzando de 1 en 1, por lo que se ejecuta 6 veces.'),(817,32,'Si una variable se declara dentro de un ciclo \'For\', ¿se puede acceder a ella fuera del ciclo en lenguajes con \'Block Scope\'?','Sí, siempre.','Solo si el ciclo se ejecutó más de 10 veces.','No, la variable solo existe dentro del bloque del ciclo.','Solo si es una constante.','C','El alcance (scope) define que las variables declaradas dentro de llaves {} o bloques suelen morir al salir de ellos.'),(818,32,'¿Qué valor toma la variable resultado?\nSi 2 % 2 == 0 Entonces\n    resultado <- \'Par\'\nSino\n    resultado <- \'Impar\'\nFinSi','Error','Cero','No cambia','Par','D','Porque 2 % 2 es 0, la condición determina que el número es \'Par\'.'),(819,32,'Si quieres intercambiar los valores de a y b sin perder ninguno, ¿cuál enfoque es el más seguro en un algoritmo básico?','Asignar b = a y luego a = b, sin usar nada más.','Sumar los valores: a = a + b; b = a + b; a = a - b.','Usar una variable temporal: temp = a; a = b; b = temp.','Asignar a = b y luego b = a, sin usar nada más.','C','La variable temporal conserva el valor original de a mientras se reasigna, evitando que uno de los valores se sobrescriba antes de tiempo.'),(820,32,'¿Cuál es el resultado de evaluar la condición ( 5 * 2 > 10 + 1 ) en pseudocódigo?','Error','No se puede','Falso','0','C','Se aplica lógica matemática simple comparando ambas expresiones numéricas.'),(821,32,'¿Cuál opción representa correctamente la negación de (A > 0 AND B <= 10) usando las leyes de De Morgan?','NOT(A > 0) AND NOT(B <= 10)','A <= 0 AND B > 10','A <= 0 OR B > 10','A > 0 OR B <= 10','C','NOT(X AND Y) equivale a NOT X OR NOT Y: NOT(A>0) es A<=0; NOT(B<=10) es B>10.'),(822,32,'En la jerarquía de operadores matemáticos, ¿cuál se ejecuta primero?','Suma y Resta.','Multiplicación y División.','Paréntesis.','Asignación (=).','C','Los paréntesis tienen la prioridad más alta para agrupar operaciones, seguidos de potencias, raíces, mult/div y sum/rest.'),(823,32,'¿Cuál es la función principal de un algoritmo?','Definir una serie de pasos ordenados y finitos para resolver un problema.','Diseñar interfaces gráficas atractivas.','Escribir código que solo las computadoras entiendan.','Aumentar la velocidad del procesador.','A','Un algoritmo es una receta lógica: debe ser finito, preciso y resolver una situación específica independientemente del lenguaje.'),(824,32,'En pseudocódigo, ¿qué representa una variable?','Una instrucción que repite código','Un espacio de memoria donde se puede almacenar un valor que puede cambiar','Una comparación lógica','Un valor fijo que nunca cambia','B','Una variable es un contenedor cuyo valor puede modificarse durante la ejecución del algoritmo.'),(825,32,'¿Qué diferencia al ciclo \'Do-While\' del ciclo \'While\'?','El Do-While es más rápido.','El Do-While evalúa la condición al final, garantizando al menos una ejecución del bloque.','El While solo funciona con números enteros.','No hay diferencia, son sinónimos en todos los lenguajes.','B','A diferencia del \'While\' estándar, el \'Do-While\' ejecuta el cuerpo del ciclo primero y luego pregunta si debe continuar.'),(826,32,'¿Qué valor booleano resulta de: NOT(5 == 5)?','5','True','False','Null','C','5 == 5 es True. El operador NOT invierte el valor, convirtiéndolo en False.'),(827,32,'Para validar una contraseña no vacía, ¿cuál condición es adecuada?','si longitud(contraseña) < 0','si contraseña == \'\' o longitud(contraseña) > 0','si longitud(contraseña) >= -1','si longitud(contraseña) > 0','D','Una contraseña no vacía implica longitud estrictamente mayor que 0.'),(828,32,'¿Qué sucede con la variable \'suma\' en: suma = 0; para i desde 1 hasta 4: si i == 3 entonces continuar; suma = suma + i?','suma = 7','suma = 3','suma = 10','suma = 6','A','Se omite i=3 por \'continuar\'; se suman 1, 2 y 4 → 7.'),(829,32,'Si NOT(Falso) se evalúa en pseudocódigo, ¿qué devuelve?','Verdadero','Error','No se puede evaluar','Cero','A','Aplicación de reglas básicas de lógica proposicional en programación.'),(830,32,'¿Qué problema describe mejor un error de \'off-by-one\' (desfase de uno) en ciclos?','El ciclo no modifica su contador.','El ciclo se ejecuta infinitamente por una condición siempre verdadera.','El ciclo itera una vez más o una vez menos de lo esperado por usar < en lugar de <= (o viceversa).','El ciclo nunca inicia.','C','El error de desfase de uno ocurre por límites incorrectos en la condición del ciclo.'),(831,32,'¿Cuál es el resultado de evaluar la condición ( 6 * 2 > 10 + 1 ) en pseudocódigo?','Error','0','No se puede','Verdadero','D','Se aplica lógica matemática simple comparando ambas expresiones numéricas.'),(832,32,'Al calcular el promedio de N valores ingresados por el usuario, ¿qué estructura es más apropiada si se conoce N de antemano?','Un \'mientras verdadero\' sin condición de salida.','Un ciclo \'para\' con N iteraciones.','Solo condicionales, sin ciclos.','Un \'según\' con N casos.','B','Cuando se conoce el número fijo de repeticiones, un \'para\' es directo y claro.'),(833,32,'¿Cuál es el resultado de evaluar la condición ( 7 * 2 > 10 + 1 ) en pseudocódigo?','No se puede','Verdadero','0','Error','B','Se aplica lógica matemática simple comparando ambas expresiones numéricas.'),(834,32,'En pseudocódigo, si i empieza en 1 y mientras i <= 5 haces i = i + 2, ¿cuántas veces se ejecuta el cuerpo del ciclo?','4 veces','2 veces','5 veces','3 veces','D','Los valores de i serán 1, 3 y 5. Se ejecuta 3 veces antes de que i pase a 7 y falle la condición.'),(835,32,'¿Cuántas veces puede ejecutarse este ciclo?\ni <- 0\nRepetir\n    i <- i + 1\nHasta Que i == 8','7','8','10','Depende del lenguaje','B','El ciclo incrementa i hasta llegar a 8, por lo que se ejecuta 8 veces.'),(836,32,'¿Qué valor toma la variable resultado?\nSi 19 % 2 == 0 Entonces\n    resultado <- \'Par\'\nSino\n    resultado <- \'Impar\'\nFinSi','Impar','Error','No cambia','Cero','A','Porque 19 % 2 es 1, la condición determina que el número es \'Impar\'.'),(837,32,'¿Qué operador en la mayoría de los lenguajes se utiliza para verificar si dos valores son DISTINTOS?','NaN','!=','<>','=','B','El operador de desigualdad es \'!=\' en la mayoría de lenguajes modernos (C, Java, Python, JS).'),(838,32,'Si se cumple que (a > b) y (b > c), entonces lógicamente ¿qué se deduce?','a > c','Cero','Error','No se puede evaluar','A','Aplicación de reglas básicas de lógica proposicional en programación.'),(839,32,'Si un ciclo debe ejecutarse mientras la variable \'energía\' sea mayor a 0, ¿cuál es la condición correcta?','energia != 0','energia > 0','energia == 0','energia < 0','B','La condición debe ser verdadera para que el ciclo continúe; por lo tanto, \'energia > 0\' es la que valida la permanencia.'),(840,32,'¿Cuál es la condición correcta para repetir la lectura de una nota hasta que esté en el rango [0, 5]?','mientras nota < 0 y nota > 5','mientras nota == 0 y nota == 5','mientras nota < 0 o nota > 5','mientras nota <= 0 o nota >= 5','C','Se repite mientras esté fuera del rango; es decir, si es menor que 0 o mayor que 5.'),(841,32,'¿Cuántas veces se ejecuta el siguiente ciclo?\nPara i = 1 Hasta 8 Con Paso 1 Hacer\n    Mostrar i\nFinPara','9','No se puede determinar','7','8','D','El ciclo inicia en 1 y termina en 8, avanzando de 1 en 1, por lo que se ejecuta 8 veces.'),(842,32,'¿Qué sucede en un flujo de control si la condición de un \'If\' es falsa y no existe un \'Else\'?','El programa se detiene con un error.','El programa vuelve a evaluar la condición indefinidamente.','Se ejecuta el código dentro del If por defecto.','El programa salta el bloque de código del If y continúa con la siguiente instrucción fuera de él.','D','El bloque \'Else\' es opcional. Si la condición no se cumple y no hay alternativa definida, el flujo simplemente sigue su curso normal.'),(843,32,'Se requiere contar cuántos números negativos hay en una lista. ¿Cuál patrón es más adecuado?','Un ciclo sin cuerpo y solo una condición.','Un acumulador que sume los valores negativos.','Un \'según sea\' con todos los números posibles.','Un contador que aumente en 1 cada vez que un elemento sea negativo.','D','Para contar elementos que cumplen una condición se utiliza un contador, no un acumulador.'),(844,32,'¿Cuál es la forma correcta de verificar que un número N está entre 1 y 100 (incluidos)?','si N < 1 o N > 100','si N >= 1 y N <= 100','si N == 1 o N == 100','si N > 1 y N < 100','B','Incluir los límites requiere usar >= y <= en la condición compuesta.');
/*!40000 ALTER TABLE `preguntas` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `usuarios`
--

/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `usuarios` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `documento` varchar(64) NOT NULL,
  `password_hash` varchar(255) NOT NULL,
  `rol` varchar(32) NOT NULL,
  `docente_id` bigint DEFAULT NULL,
  `estudiante_id` bigint DEFAULT NULL,
  `activo` tinyint(1) NOT NULL DEFAULT '1',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_usuarios_documento` (`documento`),
  KEY `ix_usuarios_docente_id` (`docente_id`),
  KEY `ix_usuarios_estudiante_id` (`estudiante_id`),
  CONSTRAINT `fk_usuarios_docente_id` FOREIGN KEY (`docente_id`) REFERENCES `docentes` (`id`),
  CONSTRAINT `fk_usuarios_estudiante_id` FOREIGN KEY (`estudiante_id`) REFERENCES `estudiantes` (`id`),
  CONSTRAINT `chk_usuarios_linked` CHECK ((((`rol` = _utf8mb4'ADMIN') and (`docente_id` is null) and (`estudiante_id` is null)) or ((`rol` = _utf8mb4'DOCENTE') and (`docente_id` is not null) and (`estudiante_id` is null)) or ((`rol` = _utf8mb4'ESTUDIANTE') and (`estudiante_id` is not null) and (`docente_id` is null))))
) ENGINE=InnoDB AUTO_INCREMENT=143 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

